const isEmptyObject = (obj: any) =>
  obj == null ||
  (Object.prototype.toString.call(obj) === '[object Object]' && Object.keys(obj).length === 0) ||
  (Array.isArray(obj) && obj.length === 0)

// 解析徽标颜色：符合“group.type 有/无”的不同优先级
const resolveBadgeColor = (t: TrackItem): string => {
  const hasGroupType = !!t.group?.type

  if (hasGroupType) {
    // group.type 已定义：group.style.color -> style.color -> 灰色
    const res = t.style?.color || t.group?.style?.color || '#9e9e9e'

    console.log('resolveBadgeColor', t.name, hasGroupType, res, t.style, t.group?.style?.color)
    return res
  }
  // group.type 未定义：style.color -> group.style.color -> 灰色
  // const res = t.style?.color || t.group?.style?.color || '#9e9e9e'
  const res = t.group?.style?.color || t.style?.color || '#9e9e9e'

  return res
}

// ===== 小方块徽标（动态颜色 + 组名缩写） =====
const acronym2 = (name?: string) => {
  if (!name) return 'OT'
  const words = name.replace(/[_-]+/g, ' ').trim().split(/\s+/)
  if (words.length >= 2) return (words[0][0] + words[1][0]).toUpperCase()
  return words[0].slice(0, 2).toUpperCase()
}
const TypeBadge: React.FC<{ label?: string; color?: string; size?: number }> = ({
  label,
  color,
  size = BADGE_SIZE
}) => {
  const shown = acronym2(label)
  const fill = color || '#9e9e9e'
  return (
    <Tooltip title={label || shown} arrow enterDelay={250} placement='right'>
      <Box
        component='span'
        role='img'
        aria-label={label || shown}
        sx={{
          width: size,
          height: size,
          display: 'inline-flex',
          alignItems: 'center',
          justifyContent: 'center',
          borderRadius: '3px',
          backgroundColor: fill,
          color: '#fff',
          fontSize: size <= 16 ? 10 : 11,
          fontWeight: 700,
          lineHeight: 1,
          flex: '0 0 auto',
          userSelect: 'none',
          mr: 0.75
        }}>
        {shown}
      </Box>
    </Tooltip>
  )
}

// ===== 数据类型与工具 =====
type TrackItem = {
  id?: string
  name?: string
  style?: { color?: string; [k: string]: any }
  group?: { name?: string; style?: { color?: string; [k: string]: any }; [k: string]: any }
  assay?: string
  cell?: string
  file_format?: string
  [k: string]: any
}
type Group = { key: string; label: string; color?: string; items: TrackItem[] }

/** 分组：按 group.name；组内保持原输入顺序；组颜色默认取 group.style.color（若为空看任一 item.style.color）；分组顺序按首次出现 */
const buildGroupsByGroupName = (rows: TrackItem[] | undefined): Group[] => {
  if (!rows || rows.length === 0) return []
  const map = new Map<string, Group>()
  for (const r of rows) {
    const key = r.group?.name || 'Other'
    if (!map.has(key)) {
      map.set(key, {
        key,
        label: key,
        color: r.group?.style?.color || r.style?.color,
        items: []
      })
    }
    const g = map.get(key)!
    // 若分组颜色未定，补上一个
    if (!g.color) g.color = r.group?.style?.color || r.style?.color
    g.items.push(r)
  }
  return Array.from(map.values())
}

// 生成副标题：assay • cell • format
const composeSecondary = (t: TrackItem) => [t.assay, t.cell, t.file_format].filter(Boolean).join(' • ')

const TrackList: FC<Iprops> = ({ trackListData, height }) => {
  const dispatch = useAppDispatch()

  // 统一为数组
  const rows = React.useMemo<TrackItem[]>(() => {
    if (Array.isArray(trackListData)) return trackListData as TrackItem[]
    if (!trackListData || typeof trackListData !== 'object') return []
    return Object.values(trackListData) as TrackItem[]
  }, [trackListData])

  // 拖拽排序相关状态
  const [isDragging, setIsDragging] = React.useState(false)
  const [draggedTrack, setDraggedTrack] = React.useState<TrackItem | null>(null)
  const [draggedIndex, setDraggedIndex] = React.useState<number>(-1)
  const [previewOrder, setPreviewOrder] = React.useState<TrackItem[]>([])
  const listRef = React.useRef<HTMLUListElement>(null)

  // 使用预览顺序或原始顺序
  const displayRows = isDragging && previewOrder.length > 0 ? previewOrder : rows

  // 搜索框
  const [query, setQuery] = React.useState('')
  const [debounced, setDebounced] = React.useState(query)
  React.useEffect(() => {
    const t = setTimeout(() => setDebounced(query.trim().toLowerCase()), 180)
    return () => clearTimeout(t)
  }, [query])

  const filteredRows = React.useMemo(() => {
    if (!debounced) return displayRows
    return displayRows.filter((r) => {
      const cands = [r.name, r.group?.name, r.assay, r.cell, r.file_format]
        .filter(Boolean)
        .map(String)
        .map((s) => s.toLowerCase())
      return cands.some((s) => s.includes(debounced))
    })
  }, [displayRows, debounced])

  // 分组（按 group.name）、展开规则
  const groupsBase = React.useMemo(() => buildGroupsByGroupName(filteredRows), [filteredRows])
  const { groupsDisplay, defaultExpanded } = React.useMemo(() => {
    if (groupsBase.length === 0) return { groupsDisplay: [] as Group[], defaultExpanded: new Set<string>() }
    const total = groupsBase.reduce((acc, g) => acc + g.items.length, 0)

    // 保持“首次出现顺序”；不做额外置顶
    const ordered = [...groupsBase]

    if (ordered.length === 1) {
      return { groupsDisplay: ordered, defaultExpanded: new Set([ordered[0].key]) }
    }
    if (total > 20) {
      return { groupsDisplay: ordered, defaultExpanded: new Set([ordered[0].key]) }
    }
    return { groupsDisplay: ordered, defaultExpanded: new Set(ordered.map((g) => g.key)) }
  }, [groupsBase])

  // 折叠状态
  const [expanded, setExpanded] = React.useState<Set<string>>(defaultExpanded)
  React.useEffect(() => setExpanded(defaultExpanded), [defaultExpanded])
  const toggleGroup = (key: string) => {
    setExpanded((prev) => {
      const next = new Set(prev)
      if (next.has(key)) next.delete(key)
      else next.add(key)
      return next
    })
  }

  // 自适应高度
  const [maxHeight, setMaxHeight] = React.useState<number>(height ?? window.innerHeight - 172)
  React.useEffect(() => {
    if (height != null) return
    const onResize = () => setMaxHeight(window.innerHeight - 172)
    window.addEventListener('resize', onResize)
    return () => window.removeEventListener('resize', onResize)
  }, [height])

  const isEmpty = rows.length === 0

  // 拖拽处理函数
  const handleDragStart = React.useCallback(
    (track: TrackItem, trackIndex: number, event: React.MouseEvent) => {
      // 只允许主按钮（左键）拖拽
      if (event.button !== 0) return

      console.log('TrackList >>> 开始拖拽:', track.name, trackIndex)
      setIsDragging(true)
      setDraggedTrack(track)
      setDraggedIndex(trackIndex)
      setPreviewOrder([...rows])

      event.preventDefault()
      event.stopPropagation()
    },
    [rows]
  )

  const handleDragMove = React.useCallback(
    (event: MouseEvent) => {
      if (!isDragging || draggedIndex === -1 || !listRef.current) return

      const listElement = listRef.current
      const listRect = listElement.getBoundingClientRect()
      const mouseY = event.clientY

      // 找到鼠标位置对应的目标项
      const items = Array.from(listElement.querySelectorAll('.track-item'))
      let targetIndex = -1

      for (let i = 0; i < items.length; i++) {
        const item = items[i] as HTMLElement
        const rect = item.getBoundingClientRect()
        const midY = rect.top + rect.height / 2

        if (mouseY < midY) {
          targetIndex = i
          break
        }
      }

      if (targetIndex === -1) targetIndex = items.length - 1

      // 如果目标位置与当前位置不同，更新预览顺序
      if (targetIndex !== draggedIndex && targetIndex >= 0) {
        const newOrder = [...previewOrder]
        const [removed] = newOrder.splice(draggedIndex, 1)
        newOrder.splice(targetIndex, 0, removed)

        setPreviewOrder(newOrder)
        setDraggedIndex(targetIndex)
      }
    },
    [isDragging, draggedIndex, previewOrder]
  )

  const handleDragEnd = React.useCallback(() => {
    if (!isDragging) return

    console.log('TrackList >>> 结束拖拽')

    // 更新最终顺序到 Redux，触发 renderer 更新
    if (previewOrder.length > 0) {
      const newOrder = previewOrder.map((track) => track.index || track.name || '')
      console.log('TrackList >>> 新排序:', newOrder)

      // 更新 trackListData
      dispatch(setTrackListData(previewOrder))

      // 调用 renderer.updateSortTrack
      try {
        const renderer = (window as any).transcriptRenderer
        if (renderer && typeof renderer.updateSortTrack === 'function') {
          console.log('TrackList >>> 调用 renderer.updateSortTrack:', newOrder)
          renderer.updateSortTrack(newOrder)
        } else {
          console.warn('TrackList >>> renderer 或 updateSortTrack 方法不可用')
        }
      } catch (error) {
        console.error('TrackList >>> 调用 renderer.updateSortTrack 失败:', error)
      }
    }

    setIsDragging(false)
    setDraggedTrack(null)
    setDraggedIndex(-1)
    setPreviewOrder([])
  }, [isDragging, previewOrder, dispatch])

  // 监听全局鼠标事件
  React.useEffect(() => {
    if (!isDragging) return

    const handleMove = (e: MouseEvent) => handleDragMove(e)
    const handleUp = () => handleDragEnd()

    document.addEventListener('mousemove', handleMove)
    document.addEventListener('mouseup', handleUp)

    return () => {
      document.removeEventListener('mousemove', handleMove)
      document.removeEventListener('mouseup', handleUp)
    }
  }, [isDragging, handleDragMove, handleDragEnd])

  return (
    <Box
      sx={{
        display: { xs: 'block', sm: 'block' },
        background: 'transparent',
        height: maxHeight,
        overflowY: 'auto',
        position: 'relative'
      }}>
      <Divider sx={{ my: 0.25 }} />

      {/* 顶部搜索（吸顶） */}
      <Box
        sx={{
          position: 'sticky',
          top: 0,
          zIndex: 3,
          bgcolor: 'background.body',
          borderBottom: '1px solid',
          borderColor: 'divider',
          p: 1
        }}>
        <Input
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder='Search tracks (name, group, assay, cell, format)…'
          size='sm'
          startDecorator={<SearchIcon fontSize='small' />}
          endDecorator={
            query ? (
              <IconButton size='small' onClick={() => setQuery('')} sx={{ p: 0.25 }}>
                <CloseIcon fontSize='small' />
              </IconButton>
            ) : null
          }
          slotProps={{ input: { 'aria-label': 'Search tracks' } }}
        />
      </Box>

      {/* 空态 */}
      {isEmpty && (
        <Typography sx={{ p: '10px 5px', color: '#707070', fontSize: 14, textAlign: 'center' }}>
          No records <br /> Please load data through the button above
        </Typography>
      )}

      {/* 分组渲染 */}
      {!isEmpty && (
        <MList dense disablePadding ref={listRef}>
          {groupsDisplay.map((g) => {
            const isOpen = expanded.has(g.key)
            return (
              <React.Fragment key={g.key}>
                {/* 组标题：折叠 + 单行省略 + Tooltip + 右侧计数 */}
                <Box
                  sx={{
                    px: 1,
                    py: 0.25,
                    display: 'flex',
                    alignItems: 'center',
                    gap: 0.25,
                    minHeight: GROUP_ROW_HEIGHT,
                    height: GROUP_ROW_HEIGHT
                  }}>
                  <IconButton
                    size='small'
                    onClick={() => toggleGroup(g.key)}
                    sx={{ mr: 0.25, p: 0.25 }}
                    aria-label={isOpen ? `Collapse ${g.label}` : `Expand ${g.label}`}>
                    {isOpen ? <ExpandMoreIcon fontSize='small' /> : <KeyboardArrowRightIcon fontSize='small' />}
                  </IconButton>

                  <Tooltip title={g.label} arrow enterDelay={250} placement='top'>
                    <Typography
                      noWrap
                      sx={{
                        px: 0.5,
                        py: 0.5,
                        fontSize: 12,
                        color: 'neutral.500',
                        textTransform: 'uppercase',
                        letterSpacing: 0.3,
                        userSelect: 'none',
                        flex: 1,
                        overflow: 'hidden',
                        textOverflow: 'ellipsis'
                      }}>
                      {g.label}
                    </Typography>
                  </Tooltip>

                  <Typography
                    component='span'
                    sx={{
                      fontSize: 12,
                      color: 'neutral.500',
                      minWidth: 24,
                      textAlign: 'right',
                      ml: 0.5,
                      flex: '0 0 auto'
                    }}>
                    {g.items.length}
                  </Typography>
                </Box>

                {/* 组内容 */}
                {isOpen &&
                  g.items.map((t, i) => {
                    const key = t.id ?? `${t.name ?? 'track'}-${i}`
                    const secondary = composeSecondary(t)

                    // 计算全局索引
                    const globalIndex = displayRows.findIndex(
                      (row) =>
                        (row.id && row.id === t.id) ||
                        (row.index && row.index === t.index) ||
                        (row.name && row.name === t.name)
                    )

                    // ✨ 使用新的颜色解析
                    const badgeColor = resolveBadgeColor(t)

                    const isDraggingThis =
                      isDragging &&
                      draggedTrack &&
                      ((draggedTrack.id && draggedTrack.id === t.id) ||
                        (draggedTrack.index && draggedTrack.index === t.index) ||
                        (draggedTrack.name && draggedTrack.name === t.name))

                    return (
                      <ListItemButton
                        key={key}
                        dense
                        className='track-item'
                        sx={{
                          pr: '2px',
                          gap: 0.5,
                          alignItems: 'center',
                          height: ROW_HEIGHT,
                          minHeight: ROW_HEIGHT,
                          py: 0,
                          cursor: ENABLE_DRAG_SORT && isDragging ? 'grabbing' : ENABLE_DRAG_SORT ? 'grab' : 'default',
                          opacity: ENABLE_DRAG_SORT && isDraggingThis ? 0.5 : 1,
                          backgroundColor: ENABLE_DRAG_SORT && isDraggingThis ? 'rgba(0,123,255,0.1)' : 'transparent',
                          transition: 'opacity 0.2s, background-color 0.2s',
                          '& .MuiListItemText-root': { my: 0 }
                        }}>
                        {/* 拖拽手柄 - 仅在启用时显示 */}
                        {ENABLE_DRAG_SORT && (
                          <IconButton
                            size='small'
                            onMouseDown={(e) => handleDragStart(t, globalIndex, e)}
                            sx={{
                              p: 0,
                              minWidth: 0,
                              opacity: 0.3,
                              cursor: 'grab',
                              '&:hover': { opacity: 0.7 },
                              '&:active': { cursor: 'grabbing' }
                            }}
                            aria-label='Drag to reorder'>
                            <DragIndicatorIcon sx={{ fontSize: 16 }} />
                          </IconButton>
                        )}

                        <TypeBadge label={t.group?.name} color={badgeColor} />
                        <MListItemText
                          primary={t.name ?? 'Unnamed'}
                          secondary={secondary}
                          primaryTypographyProps={{ fontSize: 12, lineHeight: 1.1 }}
                          secondaryTypographyProps={{ fontSize: 7, color: 'text.disabled', lineHeight: 1.1 }}
                          sx={{
                            pl: '2px',
                            m: 0,
                            whiteSpace: 'nowrap',
                            overflow: 'hidden',
                            textOverflow: 'ellipsis',
                            flex: 1
                          }}
                        />
                        {/* 右侧菜单（悬浮显示） - 仅在启用时显示 */}
                        {ENABLE_TRACK_SETTINGS && (
                          <Box
                            sx={{
                              ml: 'auto',
                              display: 'flex',
                              alignItems: 'center',
                              backgroundColor: 'transparent',
                              gap: 0,
                              opacity: 0,
                              transition: 'opacity 0.2s',
                              '.MuiListItemButton-root:hover &': { opacity: 1 }
                            }}>
                            <RowMenu trackData={t} />
                          </Box>
                        )}
                      </ListItemButton>
                    )
                  })}

                <Divider sx={{ my: 0.25 }} />
              </React.Fragment>
            )
          })}
        </MList>
      )}

      {/* 移动端分页示例（如需分页可接入真实状态） */}
      {/* <Box className='Pagination-mobile' sx={{ display: { xs: 'flex', md: 'none' }, alignItems: 'center', py: 2 }}>
        <IconButton aria-label='previous page' variant='outlined' color='neutral' size='small'>
          <KeyboardArrowLeftIcon />
        </IconButton>
        <Typography level='body-sm' sx={{ mx: 'auto' }}>
          Page 1 of 10
        </Typography>
        <IconButton aria-label='next page' variant='outlined' color='neutral' size='small'>
          <KeyboardArrowRightIcon2 />
        </IconButton>
      </Box> */}
    </Box>
  )
}

export default React.memo(TrackList)
