import React, { memo } from 'react'
import type { FC, ReactNode } from 'react'
import { Layout } from 'antd'
const { Sider } = Layout
import {
  DatabaseOutlined,
  BulbOutlined,
  LogoutOutlined,
  MenuUnfoldOutlined,
  MenuFoldOutlined,
  PlusSquareOutlined,
  BookOutlined,
  CloudServerOutlined,
  AppstoreAddOutlined,
  HistoryOutlined,
  SearchOutlined
} from '@ant-design/icons'
import { AsiderWrapper } from './style'
import Tooltip from '@mui/material/Tooltip'

interface Iprops {
  children?: ReactNode
  getAsideElement: any
}

const RightAsider: FC<Iprops> = (props) => {
  const { getAsideElement } = props
  const handleSideClick = (label) => {
    getAsideElement(label)
  }

  return (
    <AsiderWrapper>
      <Sider style={{ width: '30px', height: '100%', zIndex: 2 }} width='38px'>
        <div className='sider-container'>
          <Tooltip title='Expand' arrow enterDelay={250} placement='right'>
            <MenuFoldOutlined
              key='home'
              className='aside-btn'
              onClick={() => {
                handleSideClick('right_expand')
              }}
            />
          </Tooltip>
        </div>
      </Sider>
    </AsiderWrapper>
  )
}

export default memo(RightAsider)
