import * as React from 'react'
import type { FC, ReactNode, ButtonHTMLAttributes } from 'react'
import Button, { ButtonProps } from '@mui/joy/Button'
import { SxProps } from '@mui/joy/styles/types'

interface BaimoButtonProps extends Omit<ButtonProps, 'children' | 'size'> {
  children?: ReactNode
  /** sm≈30px, md≈40px, lg≈48px */
  size?: 'sm' | 'md' | 'lg'
  /** 是否在存在 endDecorator 时将其推到最右边（默认 true） */
  rightAlignEndDecorator?: boolean
  sx?: SxProps
}

const RADIUS = 8

const BaimoButton: FC<BaimoButtonProps> = ({
  children,
  color = 'primary',
  variant = 'solid',
  size = 'md',
  rightAlignEndDecorator = true,
  sx,
  startDecorator,
  endDecorator,
  ...rest
}) => {
  const heightMap: Record<'sm' | 'md' | 'lg', number> = { sm: 30, md: 40, lg: 48 }

  // 当存在 endDecorator 且需要右对齐时，使用 space-between；
  // 否则维持 Joy 的默认布局（带 gap 的 inline-flex）
  const shouldSpaceBetween = Boolean(endDecorator) && rightAlignEndDecorator

  return (
    <Button
      color={color}
      variant={variant}
      size={size}
      startDecorator={startDecorator}
      endDecorator={endDecorator}
      sx={[
        {
          borderRadius: `${RADIUS}px`,
          height: heightMap[size],
          px: 2, // 左右内边距
          fontWeight: 600,
          minWidth: 160,
          letterSpacing: 0.2,
          // 让 endDecorator 贴右侧
          justifyContent: shouldSpaceBetween ? 'space-between' : undefined
          // （保持默认 hover/focus 由 Joy 负责；如需更浅 hover，可在这里定制）
        },
        sx as any
      ]}
      {...rest}>
      {children}
    </Button>
  )
}

export default BaimoButton
