import * as React from 'react'
import type { FC } from 'react'
import Dropdown from '@mui/joy/Dropdown'
import Menu from '@mui/joy/Menu'
import MenuItem from '@mui/joy/MenuItem'
import MenuButton from '@mui/joy/MenuButton'
import CheckRounded from '@mui/icons-material/CheckRounded'
import KeyboardArrowDownRounded from '@mui/icons-material/KeyboardArrowDownRounded'
import Box from '@mui/joy/Box'
import { SxProps } from '@mui/joy/styles/types'

export interface PillOption<T extends string = string> {
  label: string
  value: T
  disabled?: boolean
}

interface BaimoSelectProps<T extends string = string> {
  label?: string
  value: T
  options: PillOption<T>[]
  onChange: (next: T) => void
  color?: 'primary' | 'neutral' | 'danger' | 'success' | 'warning'
  size?: 'sm' | 'md' | 'lg'
  variant?: 'solid' | 'soft' | 'outlined' | 'plain'
  minMenuWidth?: number
  sx?: SxProps
  menuSx?: SxProps
}

const RADIUS = 8
// multiple
const BaimoSelect: FC<BaimoSelectProps> = ({
  label,
  value,
  options,
  onChange,
  color = 'success',
  size = 'md',
  variant = 'solid',
  minMenuWidth = 180,
  sx,
  menuSx
}) => {
  const current = options.find((o) => o.value === value)

  const heightMap: Record<'sm' | 'md' | 'lg', number> = { sm: 30, md: 40, lg: 48 }

  // 让 Menu 宽度与 MenuButton 一致
  const btnRef = React.useRef<HTMLButtonElement | null>(null)
  const [menuWidth, setMenuWidth] = React.useState<number>(minMenuWidth)

  React.useEffect(() => {
    const setWidth = () => setMenuWidth(btnRef.current?.offsetWidth ?? minMenuWidth)
    setWidth()
    window.addEventListener('resize', setWidth)
    return () => window.removeEventListener('resize', setWidth)
  }, [minMenuWidth])

  // palette 取值的安全封装（避免 TS 推断到联合类型报错）
  const getPaletteVars = (theme: any) => (theme.vars?.palette as any)?.[color] || {}
  const getBorderColor = (theme: any) => {
    const p = getPaletteVars(theme)
    return p.outlinedBorder ?? p.solidBg ?? theme.vars.palette.neutral.outlinedBorder
  }
  const getSoftBg = (theme: any) => {
    const p = getPaletteVars(theme)
    return p.softBg ?? p.plainHoverBg
  }
  const getSoftHoverBg = (theme: any) => {
    const p = getPaletteVars(theme)
    return p.softHoverBg ?? p.softBg
  }

  return (
    <Dropdown>
      <MenuButton
        ref={btnRef}
        color={color}
        size={size}
        variant={variant}
        sx={[
          {
            borderRadius: `${RADIUS}px`,
            height: heightMap[size],
            px: 2,
            fontWeight: 600,
            justifyContent: 'space-between', // 左文案 + 右箭头
            minWidth: 160
          },
          sx as any
        ]}>
        {label ?? current?.label ?? 'Select'}
        <KeyboardArrowDownRounded fontSize='small' />
      </MenuButton>

      <Menu
        variant='outlined'
        sx={[
          (theme) => ({
            width: menuWidth,
            padding: 0,
            minWidth: menuWidth,
            borderRadius: `${RADIUS}px`,
            overflow: 'hidden',
            borderColor: getBorderColor(theme),
            '--List-padding': '6px'
          }),
          menuSx as any
        ]}>
        {options.map((opt) => {
          const selected = opt.value === value
          return (
            <MenuItem
              key={opt.value}
              disabled={opt.disabled}
              onClick={() => onChange(opt.value)}
              sx={[
                (theme) => ({
                  '--ListItem-minHeight': '24px', // 行高 24px
                  borderRadius: 0, // 无圆角
                  '&:hover': {
                    borderRadius: 0,
                    backgroundColor: getSoftBg(theme) // 极浅色
                  },
                  ...(selected && {
                    backgroundColor: getSoftBg(theme)
                  }),
                  display: 'flex',
                  alignItems: 'center',
                  gap: 8
                })
              ]}>
              <Box component='span' sx={{ flex: 1 }}>
                {opt.label}
              </Box>
              {selected && <CheckRounded fontSize='small' />}
            </MenuItem>
          )
        })}
      </Menu>
    </Dropdown>
  )
}

export default BaimoSelect
