import React, { memo, useState, useEffect, useMemo } from 'react'
import type { FC, ReactNode } from 'react'
import { useAppDispatch, useAppSelecter } from '@/store'
import AsideMenu from '@/views/main/c-cpns/left-asider/c-cpns/index'
import { BookMarkWraaper } from './style'
import { deleteFavoriteRegion, IRBRegion, setCurrentRegion } from '@/store/modules/rna_browser_settings'
import { nanoid } from 'nanoid'

import { Box, Typography, Divider, Input } from '@mui/joy'
import List from '@mui/material/List'
import ListItemButton from '@mui/material/ListItemButton'
import ListItemText from '@mui/material/ListItemText'
import Tooltip from '@mui/material/Tooltip'
import IconButton from '@mui/material/IconButton'
import ExpandMoreIcon from '@mui/icons-material/ExpandMore'
import KeyboardArrowRightIcon from '@mui/icons-material/KeyboardArrowRight'
import DeleteIcon from '@mui/icons-material/DeleteOutline'
import SearchIcon from '@mui/icons-material/Search'
import CloseIcon from '@mui/icons-material/Close'
import { TRANS_TYPE_META } from '@/constants/transType'

interface Iprops {
  children?: ReactNode
}

/** 转录本类型徽标 */
const TransTypeBadge: React.FC<{ transType?: string; size?: number }> = ({ transType, size = 18 }) => {
  const key = transType ?? ''
  const meta = TRANS_TYPE_META[key] ?? { color: '#9e9e9e', label: 'OT' }
  const fullName = (transType && transType.replace(/_/g, ' ')) || 'other'
  return (
    <Tooltip title={fullName} arrow enterDelay={250} placement='right'>
      <Box
        component='span'
        role='img'
        aria-label={fullName}
        sx={{
          width: size,
          height: size,
          display: 'inline-flex',
          alignItems: 'center',
          justifyContent: 'center',
          borderRadius: '3px',
          backgroundColor: meta.color,
          color: '#fff',
          fontSize: size <= 18 ? 10 : 11,
          fontWeight: 700,
          lineHeight: 1,
          flex: '0 0 auto',
          userSelect: 'none',
          mr: 0.75
        }}>
        {meta.label}
      </Box>
    </Tooltip>
  )
}

/** 展示名称（含 offset） */
const displayName = (item: IRBRegion, idx: number) => {
  const base =
    (item.trans_name ??
      (item as any).transcript_id ??
      (item as any).name ??
      (idx != null ? `Match ${idx + 1}` : 'Match')) + ''
  return item.offset !== undefined ? `${base}:${item.offset}` : base
}

/** 生成 chr:start-end 字符串 */
const locus = (r: IRBRegion | any) =>
  r?.chr && r?.start != null && r?.end != null ? `${r.chr}:${r.start}-${r.end}` : undefined

/** 是否命中搜索（大小写不敏感） */
const matchRegion = (r: IRBRegion | any, q: string) => {
  const cand = [r?.trans_name, r?.trans_id, r?.transcript_id, r?.gene_id, r?.gene_name, r?.search, locus(r)]
    .filter(Boolean)
    .map(String)
  return cand.some((s) => s.toLowerCase().includes(q))
}

/** 统一扁平化：顶层条目无 children → 1 条；有 children → 以 children 数量重复呈现父条（点击/删除仍针对父条） */
type LeafItem = {
  id: string
  region: IRBRegion
  name: string
  trans_id?: string
  trans_type?: string
}
const flattenFavorites = (favorites: IRBRegion[] | any[]): LeafItem[] => {
  const out: LeafItem[] = []
  favorites?.forEach((item: IRBRegion, idx: number) => {
    const name = displayName(item, idx)
    const children = (item as any).children
    if (Array.isArray(children) && children.length > 0) {
      children.forEach((_: any, ci: number) => {
        out.push({
          id: item.id ?? `${name}-${idx}-${ci}`,
          region: item,
          name,
          trans_id: item.trans_id,
          trans_type: item.trans_type
        })
      })
    } else {
      out.push({
        id: item.id ?? `${name}-${idx}`,
        region: item,
        name,
        trans_id: item.trans_id,
        trans_type: item.trans_type
      })
    }
  })
  return out
}

/** 分组：优先 favoriteCategory，其次 trans_type，最后 other；组内保持输入顺序 */
type Group = { key: string; label: string; items: LeafItem[]; sortKey: string }
const formatTitle = (s: string) => (s || '').replace(/_/g, ' ').replace(/(^|\s)[a-z]/g, (m) => m.toUpperCase())
const buildGroups = (list: LeafItem[]): Group[] => {
  const map = new Map<string, LeafItem[]>()
  for (const it of list) {
    const key = (it.region.favoriteCategory || it.trans_type || 'other') as string
    if (!map.has(key)) map.set(key, [])
    map.get(key)!.push(it)
  }
  const groups: Group[] = []
  for (const [key, items] of map) {
    const label = formatTitle(key)
    groups.push({ key, label, items, sortKey: label.toLowerCase() })
  }
  groups.sort((a, b) => a.sortKey.localeCompare(b.sortKey))
  return groups
}

const BookMark: FC<Iprops> = () => {
  const { favoriteRegions } = useAppSelecter((state) => ({
    favoriteRegions: state.rbSettings.favoriteRegions as IRBRegion[] | undefined
  }))
  const dispatch = useAppDispatch()

  const handleSelectedClick = (currentRegion: IRBRegion) => {
    dispatch(setCurrentRegion(currentRegion))
  }
  const handleDeleteClick = (currentRegion: IRBRegion) => {
    dispatch(deleteFavoriteRegion(currentRegion))
  }

  /** 搜索框状态 + 去抖 */
  const [query, setQuery] = useState('')
  const [debounced, setDebounced] = useState(query)
  useEffect(() => {
    const t = setTimeout(() => setDebounced(query.trim()), 180)
    return () => clearTimeout(t)
  }, [query])

  /** 扁平化 → 过滤 → 分组 */
  const { groupsDisplay, defaultExpanded } = useMemo(() => {
    const flat = flattenFavorites(favoriteRegions ?? [])
    const q = debounced.toLowerCase()
    const filtered = q ? flat.filter((li, idx) => matchRegion(li.region, q) || li.name.toLowerCase().includes(q)) : flat

    // 分组
    let groups = buildGroups(filtered)

    // protein_coding 置顶（若存在）
    const idxPC = groups.findIndex((g) => g.key === 'protein_coding')
    if (idxPC > -1) {
      const [pc] = groups.splice(idxPC, 1)
      groups = [pc, ...groups]
    }

    // 默认展开规则
    const total = filtered.length
    let expanded = new Set<string>()
    if (groups.length === 1) {
      expanded = new Set([groups[0].key])
    } else if (groups.length > 1 && total > 20) {
      expanded = new Set([idxPC > -1 ? 'protein_coding' : groups[0].key])
    } else {
      expanded = new Set(groups.map((g) => g.key)) // ≤20：全部展开
    }

    return { groupsDisplay: groups, defaultExpanded: expanded }
  }, [favoriteRegions, debounced])

  /** 折叠状态：随分组变化重置 */
  const [expanded, setExpanded] = useState<Set<string>>(defaultExpanded)
  useEffect(() => {
    setExpanded(defaultExpanded)
  }, [defaultExpanded])

  const toggleGroup = (key: string) => {
    setExpanded((prev) => {
      const next = new Set(prev)
      if (next.has(key)) next.delete(key)
      else next.add(key)
      return next
    })
  }

  return (
    <BookMarkWraaper>
      <AsideMenu name='Favorites' />

      <div className='content'>
        {/* 顶部搜索框（吸顶） */}
        <Box
          sx={{
            position: 'sticky',
            top: 0,
            zIndex: 3,
            bgcolor: 'background.body',
            borderBottom: '1px solid',
            borderColor: 'divider',
            p: 1
          }}>
          <Input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder='Search bookmarks (name, id, gene, chr:start-end, offset)…'
            size='sm'
            startDecorator={<SearchIcon fontSize='small' />}
            endDecorator={
              query ? (
                <IconButton size='small' onClick={() => setQuery('')} sx={{ p: 0.25 }}>
                  <CloseIcon fontSize='small' />
                </IconButton>
              ) : null
            }
            slotProps={{ input: { 'aria-label': 'Search bookmarks' } }}
          />
        </Box>

        {/* 分组列表（与 Home 相同的组标题渲染：右侧计数、单行省略 + Tooltip、可折叠） */}
        <List dense disablePadding>
          {groupsDisplay.map((g) => {
            const isOpen = expanded.has(g.key)
            return (
              <React.Fragment key={g.key}>
                {/* 组标题 */}
                <Box sx={{ px: 1, py: 0.25, display: 'flex', alignItems: 'center', gap: 0.25 }}>
                  <IconButton
                    size='small'
                    onClick={() => toggleGroup(g.key)}
                    sx={{ mr: 0.25, p: 0.25 }}
                    aria-label={isOpen ? `Collapse ${g.label}` : `Expand ${g.label}`}>
                    {isOpen ? <ExpandMoreIcon fontSize='small' /> : <KeyboardArrowRightIcon fontSize='small' />}
                  </IconButton>

                  {/* Label 单行省略 + Tooltip，数字右对齐 */}
                  <Tooltip title={g.label} arrow enterDelay={250} placement='top'>
                    <Typography
                      noWrap
                      sx={{
                        px: 0.5,
                        py: 0.5,
                        fontSize: 12,
                        color: 'neutral.500',
                        textTransform: 'uppercase',
                        letterSpacing: 0.3,
                        userSelect: 'none',
                        flex: 1,
                        overflow: 'hidden',
                        textOverflow: 'ellipsis'
                      }}>
                      {g.label}
                    </Typography>
                  </Tooltip>
                  <Typography
                    component='span'
                    sx={{
                      fontSize: 12,
                      color: 'neutral.500',
                      fontWeight: 500,
                      minWidth: 24,
                      textAlign: 'right',
                      ml: 0.5,
                      flex: '0 0 auto'
                    }}>
                    {g.items.length}
                  </Typography>
                </Box>

                {/* 组内容 */}
                {isOpen &&
                  g.items.map((li, i) => {
                    const key = li.id ?? `${li.name}-${i}`
                    const region = li.region
                    return (
                      <ListItemButton
                        key={key}
                        dense
                        onClick={() => handleSelectedClick(region)}
                        sx={{ pr: '5px', gap: 0, alignItems: 'center' }}>
                        <TransTypeBadge transType={region.trans_type} />
                        <ListItemText
                          primary={li.name}
                          secondary={region.trans_id ?? ''}
                          primaryTypographyProps={{ fontSize: 12 }}
                          secondaryTypographyProps={{ fontSize: 7, color: 'text.disabled' }}
                          sx={{
                            pl: '5px',
                            m: 0,
                            whiteSpace: 'nowrap',
                            overflow: 'hidden',
                            textOverflow: 'ellipsis'
                          }}
                        />

                        {/* 右侧删除按钮（悬浮可见） */}
                        <Box
                          sx={{
                            ml: 'auto',
                            display: 'flex',
                            alignItems: 'center',
                            backgroundColor: 'transparent',
                            gap: 0,
                            opacity: 0,
                            transition: 'opacity 0.2s',
                            '.MuiListItemButton-root:hover &': { opacity: 1 }
                          }}>
                          <IconButton
                            size='small'
                            onClick={(e) => {
                              e.stopPropagation()
                              handleDeleteClick(region)
                            }}
                            sx={{
                              backgroundColor: 'red.200',
                              color: 'grey.500',
                              p: 0.25,
                              fontWeight: 100,
                              fontSize: 18
                            }}>
                            <DeleteIcon fontSize='inherit' />
                          </IconButton>
                        </Box>
                      </ListItemButton>
                    )
                  })}
                <Divider sx={{ my: 0.5 }} />
              </React.Fragment>
            )
          })}
        </List>

        {!favoriteRegions && (
          <Typography sx={{ p: '10px 5px', color: '#707070', fontSize: 14, textAlign: 'center' }}>
            No records <br /> Please add data using the star button in RNA Browser
          </Typography>
        )}
        {favoriteRegions && favoriteRegions.length > 0 && groupsDisplay.length === 0 && (
          <Typography sx={{ p: '10px 5px', color: '#707070', fontSize: 14, textAlign: 'center' }}>
            No records <br /> Try another keyword.
          </Typography>
        )}
      </div>
    </BookMarkWraaper>
  )
}

export default memo(BookMark)
