export type FileType =
  | 'auto'
  | 'bigwig'
  | 'bigbed'
  | 'bed'
  | 'rmgff'
  | 'rmbed'
  | 'bedgraph'
  | 'gtf'
  | 'gff'
  | 'vcf'
  | 'bam'
  | 'error'

export const normalizeFileType = (fileName: string): FileType => {
  const lowerCaseFileName = fileName.toLowerCase()

  if (lowerCaseFileName.endsWith('bigwig') || lowerCaseFileName.endsWith('bw')) {
    return 'bigwig'
  } else if (lowerCaseFileName.endsWith('bigbed') || lowerCaseFileName.endsWith('bb')) {
    return 'bigbed'
  } else if (lowerCaseFileName.endsWith('bed')) {
    return 'bed'
  } else if (lowerCaseFileName.endsWith('rmgff')) {
    return 'rmgff'
  } else if (lowerCaseFileName.endsWith('rmbed')) {
    return 'rmbed'
  } else if (lowerCaseFileName.endsWith('bedgraph') || lowerCaseFileName.endsWith('bg')) {
    return 'bedgraph'
  } else if (lowerCaseFileName.endsWith('gtf')) {
    return 'gtf'
  } else if (lowerCaseFileName.endsWith('gff')) {
    return 'gff'
  } else if (lowerCaseFileName.endsWith('vcf')) {
    return 'vcf'
  } else if (lowerCaseFileName.endsWith('bam')) {
    return 'bam'
  } else {
    return 'error'
  }
}
