import React, { memo, useState, useEffect, useMemo } from 'react'
import type { FC, ReactNode } from 'react'
import { Button, Dropdown, message, Modal } from 'antd'
import type { MenuProps } from 'antd'
// import { ExclamationCircleOutlined } from '@ant-design/icons'
import MenuData from '@/config/menu-data'
import { MainMenuWrapper } from './style'
import HomeIcon from '@/assets/img/logo.png'
import { Input, Stack } from '@mui/joy'
import { InputBase } from '@mui/material'
import { Dialog, DialogTitle, DialogContent, DialogActions, Typography } from '@mui/material'
import { nanoid } from 'nanoid'
import { useAppDispatch, useAppSelecter } from '@/store'
import { setCurrentRegion, setHistoryIndex } from '@/store/modules/rna_browser_settings'

interface Iprops {
  children?: ReactNode
}

const MainMenu: FC<Iprops> = () => {
  const dispatch = useAppDispatch()
  const { historyRegions, currentHistoryIndex, selectedRegions } = useAppSelecter((state) => ({
    historyRegions: state.rbSettings.historyRegions,
    currentHistoryIndex: state.rbSettings.currentHistoryIndex,
    selectedRegions: state.rbSettings.selectedRegions
  }))

  // const { file_options, edit_options, data_options, selection_options, view_options, tracks_options, help_options } =
  //   MenuData
  const {
    file_options,
    history_options,
    selection_options,
    view_options,
    tracks_options,
    scenario_options,
    help_options
  } = MenuData
  const [uploadModal, uploadModalHolder] = Modal.useModal()
  const [modelVisible, setModelVisible] = useState(true)
  const [projectID, setProjectID] = useState('')
  const [openVersion, setOpenVersion] = useState(false)
  const [highlightVisible, setHighlightVisible] = useState(true)

  // View menu states
  const [trackLabelVisible, setTrackLabelVisible] = useState(true)
  const [gridVisible, setGridVisible] = useState(true)
  const [tooltipVisible, setTooltipVisible] = useState(true)
  const [regionHighlightVisible, setRegionHighlightVisible] = useState(true)
  const [cursorPositionVisible, setCursorPositionVisible] = useState(false)

  // Deduplicate history regions while preserving time order
  // Keep only the most recent occurrence of each unique region
  const deduplicatedHistory = useMemo(() => {
    if (!historyRegions || historyRegions.length === 0) return []

    const seen = new Map<string, number>()
    const result: typeof historyRegions = []

    // Process in reverse order (newest first) to keep track of which indices to keep
    for (let i = historyRegions.length - 1; i >= 0; i--) {
      const region = historyRegions[i]
      // Create a unique key based on the region's identifying properties
      const key = `${region.trans_id || region.trans_name || ''}_${region.chr}_${region.start}_${region.end}_${region.offset || ''}`

      if (!seen.has(key)) {
        seen.set(key, i)
        result.unshift(region) // Add to front to maintain original order
      }
    }

    return result
  }, [historyRegions])

  // Find current position in deduplicated history
  const currentDeduplicatedIndex = useMemo(() => {
    if (currentHistoryIndex < 0 || !historyRegions || historyRegions.length === 0) return -1

    const currentRegion = historyRegions[currentHistoryIndex]
    if (!currentRegion) return -1

    const currentKey = `${currentRegion.trans_id || currentRegion.trans_name || ''}_${currentRegion.chr}_${currentRegion.start}_${currentRegion.end}_${currentRegion.offset || ''}`

    return deduplicatedHistory.findIndex((region) => {
      const key = `${region.trans_id || region.trans_name || ''}_${region.chr}_${region.start}_${region.end}_${region.offset || ''}`
      return key === currentKey
    })
  }, [currentHistoryIndex, historyRegions, deduplicatedHistory])

  // Check if selectedRegions is empty
  const hasSelectedRegions = useMemo(() => {
    if (!selectedRegions || selectedRegions === '' || selectedRegions === '[]') return false
    try {
      const parsed = typeof selectedRegions === 'string' ? JSON.parse(selectedRegions) : selectedRegions
      return parsed && (Array.isArray(parsed) ? parsed.length > 0 : Object.keys(parsed).length > 0)
    } catch {
      return false
    }
  }, [selectedRegions])

  // Update history menu items based on current index in deduplicated history
  const historyMenuItems: MenuProps['items'] = [
    {
      label: 'Open History Panel',
      key: 'open'
    },
    {
      type: 'divider'
    },
    {
      label: 'Previous',
      key: 'previous',
      disabled: currentDeduplicatedIndex <= 0 || deduplicatedHistory.length === 0
    },
    {
      label: 'Next',
      key: 'next',
      disabled: currentDeduplicatedIndex >= deduplicatedHistory.length - 1 || deduplicatedHistory.length === 0
    }
  ]

  // Dynamic Selection menu items based on highlight visibility and selectedRegions
  const selectionMenuItems: MenuProps['items'] = [
    {
      label: 'Open Selection Panel',
      key: 'open'
    },
    {
      type: 'divider'
    },
    {
      label: 'Show Selection',
      key: 'show',
      disabled: !hasSelectedRegions || highlightVisible
    },
    {
      label: 'Hide Selection',
      key: 'hide',
      disabled: !hasSelectedRegions || !highlightVisible
    },
    {
      type: 'divider'
    },
    {
      label: 'Clear Selection',
      key: 'clear',
      disabled: !hasSelectedRegions
    }
  ]

  // Dynamic View menu items based on current visibility states
  const viewMenuItems: MenuProps['items'] = [
    {
      label: trackLabelVisible ? 'Hide Track Labels' : 'Show Track Labels',
      key: 'trackLabel'
    },
    {
      label: gridVisible ? 'Hide Grid Lines' : 'Show Grid Lines',
      key: 'grid'
    },
    {
      label: tooltipVisible ? 'Hide Tooltip' : 'Show Tooltip',
      key: 'tooltip'
    },
    {
      label: regionHighlightVisible ? 'Hide Region Highlights' : 'Show Region Highlights',
      key: 'regionHighlight'
    },
    {
      label: cursorPositionVisible ? 'Hide Cursor Position' : 'Show Cursor Position',
      key: 'cursorPosition'
    }
  ]

  const onClickFile: MenuProps['onClick'] = async ({ key }) => {
    switch (key) {
      case 'new':
        // Refresh page for new project
        location.reload()
        break
      case 'png':
      case 'jpeg':
      case 'svg':
      case 'pdf':
        // Export image using renderer
        await handleExportImage(key as 'png' | 'jpeg' | 'svg' | 'pdf')
        break
      default:
        message.info(`File action ${key} (coming soon)`)
    }
  }

  const handleExportImage = async (format: 'png' | 'jpeg' | 'svg' | 'pdf') => {
    const renderer = (window as any).transcriptRenderer

    if (!renderer || !renderer.exportImage) {
      message.error('Export failed: Renderer not ready')
      return
    }

    try {
      // Generate filename with current region info
      const region = renderer.config?.region
      const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, -5)
      let filename = 'transcript'

      if (region?.trans_name) {
        filename = `${region.trans_name}_${region.chr}_${region.start}-${region.end}`
      } else if (region?.chr) {
        filename = `${region.chr}_${region.start}-${region.end}`
      }

      filename = `${filename}_${timestamp}`

      // Call renderer's exportImage method with high resolution
      await renderer.exportImage(format, `${filename}.${format}`, 4)

      message.success(`Successfully exported as ${format.toUpperCase()}`)
    } catch (error) {
      console.error('Export failed:', error)
      message.error('Export failed: ' + (error instanceof Error ? error.message : 'Unknown error'))
    }
  }

  const onClickHistory: MenuProps['onClick'] = ({ key }) => {
    switch (key) {
      case 'open':
        dispatch(setHistoryIndex(historyRegions.length - 1))
        window.dispatchEvent(
          new CustomEvent('history-action', {
            detail: { action: 'open' }
          })
        )
        message.success('Opening History panel')
        break
      case 'previous':
        if (currentDeduplicatedIndex > 0 && deduplicatedHistory.length > 0) {
          const prevRegion = deduplicatedHistory[currentDeduplicatedIndex - 1]
          // Find the index of this region in the original history array
          const originalIndex = historyRegions.findIndex((r) => {
            const prevKey = `${prevRegion.trans_id || prevRegion.trans_name || ''}_${prevRegion.chr}_${prevRegion.start}_${prevRegion.end}_${prevRegion.offset || ''}`
            const rKey = `${r.trans_id || r.trans_name || ''}_${r.chr}_${r.start}_${r.end}_${r.offset || ''}`
            return prevKey === rKey
          })
          if (originalIndex >= 0) {
            dispatch(setHistoryIndex(originalIndex))
            dispatch(setCurrentRegion(prevRegion))
            message.success('Navigate to previous history')
          }
        }
        break
      case 'next':
        if (currentDeduplicatedIndex >= 0 && currentDeduplicatedIndex < deduplicatedHistory.length - 1) {
          const nextRegion = deduplicatedHistory[currentDeduplicatedIndex + 1]
          // Find the index of this region in the original history array
          const originalIndex = historyRegions.findIndex((r) => {
            const nextKey = `${nextRegion.trans_id || nextRegion.trans_name || ''}_${nextRegion.chr}_${nextRegion.start}_${nextRegion.end}_${nextRegion.offset || ''}`
            const rKey = `${r.trans_id || r.trans_name || ''}_${r.chr}_${r.start}_${r.end}_${r.offset || ''}`
            return nextKey === rKey
          })
          if (originalIndex >= 0) {
            dispatch(setHistoryIndex(originalIndex))
            dispatch(setCurrentRegion(nextRegion))
            message.success('Navigate to next history')
          }
        }
        break
      default:
        message.info(`History action ${key}`)
    }
  }

  const onClickSelection: MenuProps['onClick'] = ({ key }) => {
    window.dispatchEvent(
      new CustomEvent('selection-action', {
        detail: { action: key }
      })
    )

    // Update visibility state based on action
    if (key === 'show') {
      setHighlightVisible(true)
    } else if (key === 'hide') {
      setHighlightVisible(false)
    } else if (key === 'clear') {
      // Reset to visible state when clearing
      setHighlightVisible(true)
    }

    const messages = {
      open: 'Opening Selection panel',
      clear: 'Selection cleared',
      show: 'Selection highlights shown',
      hide: 'Selection highlights hidden'
    }
    if (messages[key]) {
      message.success(messages[key])
    } else {
      message.info(`Selection action ${key}`)
    }
  }

  const onClickTranscriptomes: MenuProps['onClick'] = ({ key }) => {
    message.info(`hover Transcriptomes index ${key} (coming soon)`)

    // uploadModal.confirm({
    //   title: 'Import Transcriptomes File',
    //   content: <UploadModal activeItem={key} thisContent={this} />,
    //   width: 800,
    //   closable: true,
    //   centered: true
    // })
  }

  const onClickView: MenuProps['onClick'] = ({ key }) => {
    switch (key) {
      case 'trackLabel':
        setTrackLabelVisible(!trackLabelVisible)
        window.dispatchEvent(
          new CustomEvent('view-action', {
            detail: { action: 'trackLabel', visible: !trackLabelVisible }
          })
        )
        message.success(trackLabelVisible ? 'Track labels hidden' : 'Track labels shown')
        break
      case 'grid':
        setGridVisible(!gridVisible)
        window.dispatchEvent(
          new CustomEvent('view-action', {
            detail: { action: 'grid', visible: !gridVisible }
          })
        )
        message.success(gridVisible ? 'Grid lines hidden' : 'Grid lines shown')
        break
      case 'tooltip':
        setTooltipVisible(!tooltipVisible)
        window.dispatchEvent(
          new CustomEvent('view-action', {
            detail: { action: 'tooltip', visible: !tooltipVisible }
          })
        )
        message.success(tooltipVisible ? 'Tooltip hidden' : 'Tooltip shown')
        break
      case 'regionHighlight':
        setRegionHighlightVisible(!regionHighlightVisible)
        window.dispatchEvent(
          new CustomEvent('view-action', {
            detail: { action: 'regionHighlight', visible: !regionHighlightVisible }
          })
        )
        message.success(regionHighlightVisible ? 'Region highlights hidden' : 'Region highlights shown')
        break
      case 'cursorPosition':
        setCursorPositionVisible(!cursorPositionVisible)
        window.dispatchEvent(
          new CustomEvent('view-action', {
            detail: { action: 'cursorPosition', visible: !cursorPositionVisible }
          })
        )
        message.success(cursorPositionVisible ? 'Cursor position hidden' : 'Cursor position shown')
        break
      default:
        message.info(`View action ${key}`)
    }
  }

  const onClickTracks: MenuProps['onClick'] = ({ key }) => {
    switch (key) {
      case 'open':
        window.dispatchEvent(
          new CustomEvent('track-action', {
            detail: { action: 'open' }
          })
        )
        message.success('Opening Tracks panel')
        break
      case 'local':
        window.dispatchEvent(
          new CustomEvent('track-action', {
            detail: { action: 'add-local' }
          })
        )
        break
      case 'remote':
        window.dispatchEvent(
          new CustomEvent('track-action', {
            detail: { action: 'add-remote' }
          })
        )
        break
      case 'datahub':
        window.dispatchEvent(
          new CustomEvent('track-action', {
            detail: { action: 'open-datahub' }
          })
        )
        break
      default:
        message.info(`Track action ${key} (coming soon)`)
    }
  }

  const onClickScenario: MenuProps['onClick'] = ({ key }) => {
    if (key === 'open') {
      window.dispatchEvent(
        new CustomEvent('scenario-panel-open', {
          detail: { action: 'open' }
        })
      )
      message.success('Opening Scenario Panel')
    } else {
      window.dispatchEvent(
        new CustomEvent('scenario-selected', {
          detail: { scenarioKey: key }
        })
      )
      message.success(`Switched to ${key} scenario`)
    }
  }

  const onClickHelp: MenuProps['onClick'] = ({ key }) => {
    switch (key) {
      case '0':
        window.open('https://doc.rbrowser.org/2_quick_start/', '_blank')
        break
      case '1':
        window.open('https://doc.rbrowser.org/2_quick_start/', '_blank')
        break
      case '2':
        window.open('https://doc.rbrowser.org/5_contact/', '_blank')
        break
      case '3':
        window.open('https://doc.rbrowser.org/1_before_starting/', '_blank')
        break
      case '4':
        setOpenVersion(true)
        break
    }
  }

  const handleProjectId = (e: React.ChangeEvent<HTMLInputElement>) => {
    console.log(e.target.value)
  }

  // Reset highlight visibility when selectedRegions becomes empty
  useEffect(() => {
    if (!hasSelectedRegions) {
      setHighlightVisible(true)
    }
  }, [hasSelectedRegions])

  useEffect(() => {
    const currentProjectId = localStorage.getItem('projectID')
    console.log('currentProjectId', currentProjectId)
    if (currentProjectId !== null) {
      console.log('currentProjectId-null', currentProjectId)
      setProjectID(currentProjectId!)
    } else {
      console.log('currentProjectId', currentProjectId)
      setProjectID(nanoid())
    }
  }, [])

  return (
    <MainMenuWrapper id='main-menu'>
      {/* <DraggableModal></DraggableModal> */}
      <Stack direction='row' spacing={1} justifyContent='space-between'>
        <Stack direction='row' spacing={1}>
          <img src={HomeIcon} className='menu-logo' />

          <Dropdown
            menu={{
              items: file_options,
              onClick: onClickFile
            }}
            trigger={['hover']}>
            <Button type='text'>File</Button>
          </Dropdown>
          {/* <Dropdown
            menu={{
              items: data_options,
              onClick: onClickTranscriptomes
            }}
            trigger={['hover']}>
            <Button type='text'>Data</Button>
          </Dropdown> */}
          <Dropdown
            menu={{
              items: tracks_options,
              onClick: onClickTracks
            }}
            trigger={['hover']}>
            <Button type='text'>Tracks</Button>
          </Dropdown>
          <Dropdown
            menu={{
              items: scenario_options,
              onClick: onClickScenario
            }}
            trigger={['hover']}>
            <Button type='text'>Scenario</Button>
          </Dropdown>
          <Dropdown
            menu={{
              items: selectionMenuItems,
              onClick: onClickSelection
            }}
            trigger={['hover']}>
            <Button type='text'>Selection</Button>
          </Dropdown>
          <Dropdown
            menu={{
              items: historyMenuItems,
              onClick: onClickHistory
            }}
            trigger={['hover']}>
            <Button type='text'>History</Button>
          </Dropdown>
          <Dropdown
            menu={{
              items: viewMenuItems,
              onClick: onClickView
            }}
            trigger={['hover']}>
            <Button type='text'>View</Button>
          </Dropdown>

          <Dropdown
            menu={{
              items: help_options,
              onClick: onClickHelp
            }}
            trigger={['hover']}>
            <Button type='text'>Help</Button>
          </Dropdown>
        </Stack>
        <Input
          disabled
          size='sm'
          sx={{ minHeight: '24px', width: '230px', boxShadow: 'none' }}
          placeholder={`Project: ${projectID}`}
          // value={nanoid()}
          // ref={(el: HTMLInputElement | null) => (inputRefs.current[i] = el)}
          onChange={handleProjectId}
        />
      </Stack>
      {uploadModalHolder}

      <Dialog
        open={openVersion}
        onClose={() => {
          setOpenVersion(false)
        }}>
        <DialogTitle>Update Status</DialogTitle>
        <DialogContent>You are already using the latest version.</DialogContent>
        <DialogActions>
          <Button
            color='primary'
            onClick={() => {
              setOpenVersion(false)
            }}
            autoFocus>
            OK
          </Button>
        </DialogActions>
      </Dialog>
    </MainMenuWrapper>
  )
}

export default memo(MainMenu)
