import React, { memo, useState } from 'react'
import type { FC, ReactNode } from 'react'
import { styled } from '@mui/material/styles'
import { Stack } from '@mui/system'
import FormControl from '@mui/joy/FormControl'
import FormLabel from '@mui/joy/FormLabel'
import Button from '@mui/joy/Button'
import Modal from '@mui/joy/Modal'
import ModalDialog from '@mui/joy/ModalDialog'
import Box from '@mui/joy/Box'

import AddCircleOutline from '@mui/icons-material/AddCircleOutline'

import { useDispatch } from 'react-redux'
import { addChannelNewData } from '@/store/modules/rna_browser_settings'

import RemoteTrack from './remote-track'
import BaimoSnackBar from '@/components/snackbar'
import { AddTrackWrapper } from './style'
import { normalizeFileType } from '@/renderer/transcript-renderer/utils/track'

// New pill-styled reusable components
import BaimoSelect from '@/components/menu-select'
import BaimoButton from '@/components/button'

interface Iprops {
  children?: ReactNode
}

const VisuallyHiddenInput = styled('input')({
  clip: 'rect(0 0 0 0)',
  clipPath: 'inset(50%)',
  height: 1,
  overflow: 'hidden',
  position: 'absolute',
  bottom: 0,
  left: 0,
  whiteSpace: 'nowrap',
  width: 1
})

export const fileTypeData = [
  { value: 'auto', label: 'Auto' },
  { value: 'bigwig', label: 'BigWig' },
  { value: 'bigbed', label: 'BigBed' },
  { value: 'bed', label: 'BED' },
  { value: 'rmgff', label: 'rmGFF' },
  { value: 'rmbed', label: 'rmBED' },
  { value: 'bedgraph', label: 'BedGraph' },
  { value: 'gtf', label: 'GTF' },
  { value: 'gff', label: 'GFF' },
  { value: 'vcf', label: 'VCF' },
  { value: 'bam', label: 'BAM' }
]

type TrackFrom = 'local' | 'remote' | 'datahub'
const trackFromOptions: { value: TrackFrom; label: string }[] = [
  { value: 'local', label: 'Local' },
  { value: 'remote', label: 'Remote' },
  { value: 'datahub', label: 'DataHub' }
]

const AddTrack: FC<Iprops> = () => {
  const [trackFrom, setTrackFrom] = React.useState<TrackFrom>('local')
  const [remoteModelOpen, setRemoteModelOpen] = useState<boolean>(false)
  const [snackbarContent, setSnackbarContent] = useState<string>('')
  const [isOpenTrackTooltip, setOpenTrackTooltip] = useState<boolean>(false)
  const isApplication = import.meta.env.VITE_IS_APPLICATION === 'true'
  const [dataHubModalOpen, setDataHubModalOpen] = useState<boolean>(false)

  const dispatch = useDispatch()

  // Listen for track actions from menu
  React.useEffect(() => {
    const handleTrackAction = (event: CustomEvent) => {
      const action = event.detail.action
      console.log('Track action from menu:', action)

      switch (action) {
        case 'add-local':
          // Simulate clicking the file input
          setTrackFrom('local')
          // Trigger file input click after a short delay to ensure UI updates
          setTimeout(() => {
            const fileInput = document.querySelector('input[type="file"]') as HTMLInputElement
            if (fileInput) {
              fileInput.click()
            }
          }, 100)
          break
        case 'add-remote':
          // Open remote track dialog
          setTrackFrom('remote')
          setRemoteModelOpen(true)
          break
        case 'open-datahub':
          // Open DataHub
          setTrackFrom('datahub')
          handleOpenDataHubClick()
          break
      }
    }

    window.addEventListener('track-action', handleTrackAction as EventListener)
    return () => {
      window.removeEventListener('track-action', handleTrackAction as EventListener)
    }
  }, [])

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0]
    if (!file) return

    const reader = new FileReader()
    reader.readAsArrayBuffer(file)
    reader.onload = (e) => {
      const result = e.target?.result
      if (!result || typeof result !== 'object') return

      const { trackName, trackFormat } = formatFileName(file)
      const normTrackFormat = normalizeFileType(trackFormat)

      if (normTrackFormat === 'error') {
        setSnackbarContent(`Unsupported file format: ${trackFormat}`)
        setOpenTrackTooltip(true)
        return
      }

      const trackSettings = [
        {
          name: trackName,
          index: '',
          method: 'local',
          format: normTrackFormat,
          url: e // keep original behavior
        }
      ]

      dispatch(addChannelNewData(trackSettings))
    }
  }

  const formatFileName = (file: File): { trackName: string; trackFormat: string } => {
    const name = file.name
    // take the last extension; support things like ".bedGraph", ".bigWig"
    const lastDot = name.lastIndexOf('.')
    if (lastDot === -1) return { trackName: name, trackFormat: '' }

    const base = name.slice(0, lastDot)
    const ext = name.slice(lastDot + 1)
    return { trackName: base, trackFormat: ext }
  }

  const handleOpenDataHubClick = () => {
    const fullUrl = window.location.origin + window.location.pathname + '#/data_hub'
    if (isApplication) {
      // 使用新 Tab 模式打开
      window.open(fullUrl, '_blank')
    } else {
      window.open(
        fullUrl,
        'DataHub',
        'width=1200,height=800,left=200,top=200,titlebar=no,status=no,toolbar=no,menubar=no,location=no'
      )
    }
  }

  const handleCloseDataHubModal = () => {
    setDataHubModalOpen(false)
  }

  // 监听来自内嵌页面（iframe）的 postMessage：当收到 { type: 'datahub:apply' } 时关闭 modal
  React.useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      const payload = event.data
      let data
      if (typeof payload === 'string') {
        try {
          data = JSON.parse(payload)
        } catch {
          data = payload
        }
      } else {
        data = payload
      }

      if (data && data.type === 'datahub:apply') {
        setDataHubModalOpen(false)
      }
    }

    window.addEventListener('message', handleMessage)
    return () => window.removeEventListener('message', handleMessage)
  }, [])

  const handleRemoteClick = () => setRemoteModelOpen(true)
  const handleCloseRemoteTrack = () => setRemoteModelOpen(false)
  const handleSnackClose = () => setOpenTrackTooltip(false)

  return (
    <AddTrackWrapper>
      <BaimoSnackBar isOpen={isOpenTrackTooltip} onClose={handleSnackClose} content={snackbarContent} variant='error' />
      <RemoteTrack isOpen={remoteModelOpen} onClose={handleCloseRemoteTrack} />

      {/* DataHub Modal */}
      <Modal open={dataHubModalOpen} onClose={handleCloseDataHubModal}>
        <ModalDialog
          variant='outlined'
          sx={{
            width: 'calc(100vw - 80px)',
            height: 'calc(100vh - 80px)',
            p: 0,
            overflow: 'hidden',
            display: 'flex',
            flexDirection: 'column'
          }}>
          <Box component='div' sx={{ flex: 1, overflow: 'hidden' }}>
            <iframe title='DataHub' src={'/#/data_hub'} style={{ width: '100%', height: '100%', border: '0' }} />
          </Box>
        </ModalDialog>
      </Modal>

      <Stack
        direction='column'
        spacing={1}
        sx={{ m: 1, minWidth: 120, width: '100%', pr: '15px', whiteSpace: 'nowrap' }}>
        {/* Step 1: Track From (Pill-style select) */}
        <FormControl size='sm' sx={{ flex: 1 }}>
          {/* <FormLabel>1. Track From</FormLabel> */}
          <BaimoSelect
            label={trackFromOptions.find((o) => o.value === trackFrom)?.label}
            value={trackFrom}
            options={trackFromOptions}
            onChange={(v) => setTrackFrom(v as TrackFrom)}
            color='primary'
            variant='solid'
            size='sm'
          />
        </FormControl>

        {/* Actions */}
        {trackFrom === 'local' && (
          <BaimoButton
            variant='solid'
            size='sm'
            color='primary'
            startDecorator={<AddCircleOutline />}
            component='label'
            role={undefined}
            tabIndex={-1}>
            Add Local Track
            <VisuallyHiddenInput type='file' onChange={handleFileChange} />
          </BaimoButton>
        )}

        {trackFrom === 'remote' && (
          <BaimoButton
            variant='solid'
            size='sm'
            color='primary'
            startDecorator={<AddCircleOutline />}
            onClick={handleRemoteClick}>
            Add Remote Track
          </BaimoButton>
        )}

        {trackFrom === 'datahub' && (
          <BaimoButton
            variant='solid'
            size='sm'
            color='primary'
            startDecorator={<AddCircleOutline />}
            onClick={handleOpenDataHubClick}>
            Open DataHub
          </BaimoButton>
        )}
      </Stack>
    </AddTrackWrapper>
  )
}

export default memo(AddTrack)
