import styled from 'styled-components'

export const BookMarkWraaper = styled.div`
  height: 100%;
  background: #ffffff;

  .content {
    overflow-y: auto;
    overflow-x: hidden;
    height: 'calc(100% - 40px)';
  }

  /* Tree */
  .ant-tree .ant-tree-node-content-wrapper.ant-tree-node-selected,
  .ant-tree .ant-tree-checkbox + span.ant-tree-node-selected {
    background-color: #4470d7;
    color: #fff;
  }
  .ant-tree .ant-tree-node-content-wrapper {
    white-space: nowrap !important;
    text-overflow: ellipsis !important;
    line-height: 22px;
    font-size: 12px;
    user-select: none;
    text-align: left;
    width: 100%;
    border-radius: 4px;
  }

  .ant-tree-title {
    font-weight: 400;
  }

  .ant-input-group > .ant-input:first-child,
  .ant-input-group .ant-input-group-addon:first-child {
    border-radius: 0;
  }

  .ant-select:not(.ant-select-disabled):not(.ant-select-customize-input):not(.ant-pagination-size-changer):hover
    .ant-select-selector {
    border: none;
    box-shadow: none;
  }

  .ant-select .ant-select-arrow {
    display: flex;
    align-items: center;
    color: rgba(0, 0, 0, 0.25);
    font-style: normal;
    line-height: 1;
    text-align: center;
    text-transform: none;
    vertical-align: -0.125em;
    text-rendering: optimizeLegibility;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    position: absolute;
    top: 50%;
    inset-inline-start: auto;
    inset-inline-end: 4px;
    height: 12px;
    margin-top: -6px;
    font-size: 12px;
    pointer-events: none;
  }

  .ant-input-group .ant-input-group-addon {
    position: relative;
    padding: 0;
    color: rgba(0, 0, 0, 0.88);
    font-weight: normal;
    font-size: 14px;
    text-align: center;
    background-color: rgba(0, 0, 0, 0);
    border: none;
    border-radius: 0px;
    transition: all 0.3s;
    line-height: 1;
  }

  .ant-select-single .ant-select-selector {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
    color: rgba(0, 0, 0, 0.88);
    font-size: 14px;
    line-height: 1.5714285714285714;
    list-style: none;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, 'Noto Sans', sans-serif,
      'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol', 'Noto Color Emoji';
    display: flex;
    border-radius: 0px;
  }

  .ant-select-single.ant-select-show-arrow .ant-select-selection-item,
  .ant-select-single.ant-select-show-arrow .ant-select-selection-placeholder {
    padding-inline-end: 25px;
  }

  .ant-select-single .ant-select-selector .ant-select-selection-item,
  .ant-select-single .ant-select-selector .ant-select-selection-placeholder {
    padding: 0 20px 0 5px;
  }

  .ant-input-group > .ant-input:last-child,
  .ant-input-group .ant-input-group-addon:last-child {
    border-radius: 0;
  }

  /* search input */
  .ant-input {
    box-sizing: border-box;
    margin: 0;
    padding: 2px 10px 2px 8px;
    color: rgba(0, 0, 0, 0.88);
    font-size: 16px;
    font-weight: 500;
    list-style: none;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, 'Noto Sans', sans-serif,
      'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol', 'Noto Color Emoji';
    position: relative;
    display: inline-block;
    width: 100%;
    min-width: 0;
    background-color: #ffffff;
    background-image: none;
    border: none;
    transition: all 0.2s;
    outline: none;
    border: none;
    box-shadow: none;
    height: 38px;
    :focus {
      outline: none;
    }
  }

  .ant-input:focus {
    border: none;
    box-shadow: none;
  }

  /* tabs */

  .ant-tabs .ant-tabs-tab.ant-tabs-tab-active .ant-tabs-tab-btn {
    color: #4d4d4d;
    text-shadow: 0 0 0.25px currentcolor;
    padding: 0 20px;
  }

  .ant-tabs .ant-tabs-ink-bar {
    position: absolute;
    background: #4d4d4d;
    pointer-events: none;
  }

  .ant-tabs .ant-tabs-tab {
    position: relative;
    display: inline-flex;
    align-items: center;
    padding: 5px 0;
    font-size: 14px;
    background: transparent;
    border: 0;
    outline: none;
    cursor: pointer;
  }

  .ant-tabs-top > .ant-tabs-nav,
  .ant-tabs-bottom > .ant-tabs-nav,
  .ant-tabs-top > div > .ant-tabs-nav,
  .ant-tabs-bottom > div > .ant-tabs-nav {
    margin: 0 0 5px 0;
  }

  /* Button */
  .ant-btn-default {
    background-color: transparent;
    border-color: transparent;
    box-shadow: none;
    border-radius: 0;

    :hover {
      border-color: transparent;
      box-shadow: none;
      border-radius: 0;
      outline: none;
    }
  }

  .ant-btn {
    font-size: 14px;
    height: 30px;
    padding: 2px 0px 2px 5px;
    border-radius: 6px;
  }

  .ant-radio-group-solid .ant-radio-button-wrapper-checked:not(.ant-radio-button-wrapper-disabled):focus-within {
    box-shadow: 0 0 0 3px transparent !important;
  }

  /* Tree */
  .ant-tree .ant-tree-node-content-wrapper.ant-tree-node-selected,
  .ant-tree .ant-tree-checkbox + span.ant-tree-node-selected {
    /* background-color: #4470d7;
    color: #fff; */
    background-color: #e3effb;
    color: #12467b;
  }
  .ant-tree .ant-tree-node-content-wrapper {
    white-space: nowrap !important;
    text-overflow: ellipsis !important;
    line-height: 24px;
    user-select: none;
    text-align: left;
    width: 100%;
    border-radius: 4px;
  }

  .ant-tree-title {
    font-size: 12px;
    font-weight: 500;
  }
`
