import React, { memo, useEffect, useState } from 'react'
import type { FC, ReactNode } from 'react'
import AsideMenu from '../../aside-menu'
import { RegionWrapper } from './style'
import { useAppSelecter, useAppDispatch, shallowEqualApp } from '@/store'

import Stack from '@mui/joy/Stack'
import Table from '@mui/joy/Table'
import Input from '@mui/joy/Input'
import { FormControl, Divider, Typography, Box, IconButton } from '@mui/joy'
import Tooltip from '@mui/material/Tooltip'
import EastIcon from '@mui/icons-material/East'
import RestartAltIcon from '@mui/icons-material/RestartAlt'

import BaimoSelect from '@/components/menu-select'
import { setSelectedRegions } from '@/store/modules/rna_browser_settings'

interface Iprops {
  children?: ReactNode
}

// ======== 行高 & 徽标常量（统一调节密度/风格） ========
const ROW_HEIGHT = 28
const GROUP_ROW_HEIGHT = 26
const BADGE_SIZE = 16

// ======== 单字符徽标（R/C/D），仅第一列显示 ========
const MODE_META: Record<string, { color: string; char: string }> = {
  rna: { color: '#1F7A1F', char: 'R' },
  cds: { color: '#7E57C2', char: 'C' },
  dna: { color: '#0B6BCB', char: 'D' },
  other: { color: '#9E9E9E', char: '?' }
}
const OneCharBadge: React.FC<{ mode?: string; size?: number; regionName?: string }> = ({
  mode,
  size = BADGE_SIZE,
  regionName
}) => {
  const key = (mode || 'other').toLowerCase()
  const meta = MODE_META[key] ?? MODE_META.other
  const content = regionName ? regionName.charAt(0).toUpperCase() : meta.char
  return (
    <Tooltip title={regionName} arrow enterDelay={250} placement='right'>
      <Box
        component='span'
        role='img'
        aria-label={meta.char}
        sx={{
          width: size,
          height: size,
          display: 'inline-flex',
          alignItems: 'center',
          justifyContent: 'center',
          borderRadius: '3px',
          backgroundColor: meta.color,
          color: '#fff',
          fontSize: size <= 16 ? 10 : 11,
          fontWeight: 700,
          lineHeight: 1,
          flex: '0 0 auto',
          userSelect: 'none'
        }}>
        {meta.char}
      </Box>
    </Tooltip>
  )
}

const Region: FC<Iprops> = () => {
  const [regions, setRegions] = useState<any[]>([])
  const [regionMode, setRegionMode] = useState<string>('dna')

  const { selectedRegions } = useAppSelecter(
    (state) => ({
      selectedRegions: state.rbSettings.selectedRegions
    }),
    shallowEqualApp
  )
  const dispatch = useAppDispatch()

  useEffect(() => {
    if (selectedRegions === '' || selectedRegions.length === 0) return
    const _regions = JSON.parse(selectedRegions as string)
    const regionObj: any[] = []
    let index = 1
    for (const region_id in _regions) {
      const regionItem = _regions[region_id]
      regionObj.push({
        num: index++,
        name: regionItem.name || region_id,
        id: regionItem.id,
        rna: {
          start: regionItem.rna.start,
          end: regionItem.rna.end,
          len: regionItem.rna.end != regionItem.rna.start ? regionItem.rna.end - regionItem.rna.start + 1 : 0
        },
        cds: {
          start: regionItem.cds.start,
          end: regionItem.cds.end,
          len: regionItem.cds.end != regionItem.cds.start ? regionItem.cds.end - regionItem.cds.start + 1 : 0
        },
        dna: {
          start: regionItem.start,
          end: regionItem.end,
          len: regionItem.end != regionItem.start ? regionItem.end - regionItem.start + 1 : 0
        },
        color: regionItem.color
      })
    }
    console.log('[regionObj]', regionObj)
    setRegions(regionObj)
  }, [selectedRegions])

  const inputStyle = {
    height: '15px',
    minHeight: '15px',
    fontSize: '12px',
    border: 'none',
    textAlign: 'end' as const,
    '--Input-radius': '0px',
    p: '2px',
    lineHeight: '15px',
    boxSizing: 'border-box' as const,
    '&:focus': {
      borderColor: 'neutral.outlinedHoverBorder',
      background: 'var(--Input-focusedHighlight)',
      color: 'white'
    },
    '&::before': {
      border: '1px solid var(--Input-focusedHighlight)',
      transform: 'scaleX(0)',
      left: 0,
      right: 0,
      bottom: '-1px',
      top: 'unset',
      transition: 'transform .15s cubic-bezier(0.1,0.9,0.2,1)',
      borderRadius: 0
    },
    '&:focus-within::before': {
      transform: 'scaleX(1)'
    }
  }

  const trackFromData = [
    { label: 'RNA Mode', value: 'rna' },
    // 🔴 CDS Mode 暂时关闭，等待调试
    // { label: 'CDS Mode', value: 'cds' },
    { label: 'DNA Mode', value: 'dna' }
  ]

  const handleRegionTypeChange = (regionType: string) => {
    if (!regionType) return
    setRegionMode(regionType)
  }

  const handleResetRegions = () => {
    // Clear regions from Redux store with empty object
    dispatch(setSelectedRegions({}))
    console.log('[Region] Cleared all selected regions')

    // Clear rendered highlights from renderer
    try {
      const renderer = (window as any).transcriptRenderer
      if (renderer && typeof renderer.renderRegionHighlights === 'function') {
        // Pass empty object to clear all highlights
        renderer.renderRegionHighlights({})
        console.log('[Region] Cleared region highlights from renderer')
      } else {
        console.warn('[Region] Renderer or renderRegionHighlights method not available')
      }
    } catch (error) {
      console.error('[Region] Failed to clear region highlights:', error)
    }
  }

  return (
    <RegionWrapper style={{ display: 'flex', flexDirection: 'column' }}>
      <AsideMenu name='Selection' />
      {/* 顶部控制条：与其他组件保持一致 */}
      <Stack
        direction='row'
        spacing={1}
        sx={{ m: 1, minWidth: 120, width: '100%', paddingRight: '15px', whiteSpace: 'nowrap' }}>
        <FormControl sx={{ flex: 1 }} size='sm'>
          <BaimoSelect
            color='primary'
            size='sm'
            variant='solid'
            value={regionMode}
            options={trackFromData}
            onChange={handleRegionTypeChange}
          />
        </FormControl>
        <Tooltip title='Clear all regions' placement='top'>
          <IconButton
            size='sm'
            variant='outlined'
            color='neutral'
            onClick={handleResetRegions}
            sx={{
              minWidth: '32px',
              width: '32px',
              height: '32px',
              padding: 0
            }}>
            <RestartAltIcon sx={{ fontSize: 18 }} />
          </IconButton>
        </Tooltip>
      </Stack>
      <Divider sx={{ my: 0.5 }} />
      {/* 标题条（无折叠逻辑，计数右对齐） */}
      <Box
        sx={{
          px: 1,
          py: 0.25,
          display: 'flex',
          alignItems: 'center',
          gap: 0.5,
          minHeight: GROUP_ROW_HEIGHT,
          height: GROUP_ROW_HEIGHT
        }}>
        <Typography
          noWrap
          sx={{
            px: 0.5,
            py: 0.5,
            fontSize: 12,
            color: 'neutral.500',
            textTransform: 'uppercase',
            letterSpacing: 0.3,
            userSelect: 'none',
            flex: 1,
            overflow: 'hidden',
            textOverflow: 'ellipsis'
          }}>
          Selected Regions ({regionMode.toUpperCase()})
        </Typography>
        <Typography
          component='span'
          sx={{ fontSize: 12, color: 'neutral.500', minWidth: 24, textAlign: 'right', ml: 0.5, flex: '0 0 auto' }}>
          {regions?.filter((region) => {
            const mode = regionMode as 'rna' | 'cds' | 'dna'
            return parseInt(region[mode].len) > 0
          }).length ?? 0}
        </Typography>
      </Box>
      {/* 表格 */}
      <Stack spacing={2} sx={{ width: '100%', flex: 1, overflow: 'hidden' }}>
        {regions && regions.length > 0 && (
          <Box sx={{ height: '100%', overflowY: 'auto' }}>
            <Table
              borderAxis='bothBetween'
              size='sm'
              stickyFooter={false}
              stickyHeader
              variant='plain'
              sx={{
                '--TableCell-height': `${ROW_HEIGHT}px`,
                '& thead th': {
                  fontSize: 12,
                  color: 'neutral.500',
                  textTransform: 'uppercase',
                  letterSpacing: 0.3,
                  backgroundColor: 'background.body'
                },
                '& tbody td': {
                  fontSize: 12,
                  lineHeight: 1.1,
                  py: 0
                },
                '& tr': { fontWeight: 600 },
                // 列宽与对齐
                '& tr > *:first-of-type': { width: 24, textAlign: 'center' }, // 徽标列
                '& tr > *:nth-of-type(2)': { textAlign: 'left' }, // 位置列
                '& tr > *:last-child': { width: 50, textAlign: 'right' } // 长度列
              }}>
              <thead>
                <tr>
                  <th></th>
                  <th>Location</th>
                  <th>LEN</th>
                </tr>
              </thead>
              <tbody>
                {regions.map((region) => {
                  const mode = regionMode as 'rna' | 'cds' | 'dna'
                  const lenValue = parseInt(region[mode].len)

                  // 仅渲染 len > 0 的行
                  if (lenValue <= 0) return null

                  const start = parseInt(region[mode].start).toLocaleString()
                  const end = parseInt(region[mode].end).toLocaleString()
                  const name = region.name
                  const len = lenValue.toLocaleString()

                  return (
                    <tr key={region.id} style={{ height: ROW_HEIGHT, minHeight: ROW_HEIGHT }}>
                      {/* 第一列：仅显示单字符徽标 */}
                      <td style={{ textAlign: 'center' }}>
                        <OneCharBadge mode={regionMode} regionName={name} />
                      </td>

                      {/* 第二列：起止位置 */}
                      <td>
                        <Box sx={{ display: 'flex', alignItems: 'center' }}>
                          <Input sx={inputStyle} value={start} />
                          <Box className='selected-arrow' sx={{ px: 0.5, display: 'flex', alignItems: 'center' }}>
                            {/* <EastIcon sx={{ fontSize: 18 }} /> */}-
                          </Box>
                          <Input sx={inputStyle} value={end} />
                        </Box>
                      </td>

                      {/* 第三列：长度 */}
                      <td>
                        <Typography level='body-sm' sx={{ fontSize: 12 }}>
                          {len}
                        </Typography>
                      </td>
                    </tr>
                  )
                })}
              </tbody>
            </Table>
          </Box>
        )}

        {regions && regions.length === 0 && (
          <Typography sx={{ p: '10px 5px', color: '#707070', fontSize: 14, textAlign: 'center' }}>
            No records
            <br />
            Please use right-click to scroll in RNA Browser (holding Ctrl allows for multiple selections)
          </Typography>
        )}
      </Stack>
    </RegionWrapper>
  )
}

export default memo(Region)
