import React, { memo, useEffect, useState } from 'react'
import type { FC, ReactNode } from 'react'
import { useAppDispatch } from '@/store'
import AsideMenu from '@/views/main/c-cpns/left-asider/c-cpns/index'
import { Button, Snackbar } from '@mui/joy'
import { ASODesignLeftSideWraaper } from './style'
import FolderOpenRounded from '@mui/icons-material/FolderOpenRounded'
import DownloadIcon from '@mui/icons-material/Download'
import CheckCircleRoundedIcon from '@mui/icons-material/CheckCircleRounded'
import { Box, Stack, Sheet, List, ListItem, ListSubheader, Typography, Divider } from '@mui/joy'
import dayjs from 'dayjs'
import relativeTime from 'dayjs/plugin/relativeTime'
import KeyboardArrowRight from '@mui/icons-material/KeyboardArrowRight'
import KeyboardArrowDown from '@mui/icons-material/KeyboardArrowDown'
import BaimoButton from '@/components/button'
import IconButton from '@mui/material/IconButton'
import ExpandMoreIcon from '@mui/icons-material/ExpandMore'
import KeyboardArrowRightIcon from '@mui/icons-material/KeyboardArrowRight'
import { Tooltip } from '@mui/material'

dayjs.extend(relativeTime)

interface Iprops {
  children?: ReactNode
}

const GROUP_ROW_HEIGHT = 26

const ASODesign: FC<Iprops> = () => {
  const [currentWindow, setCurrentWindow] = useState<Window | null>(null)
  const [downloadHistory, setDownloadHistory] = useState<{ timestamp: string; filename: string; serialized: string }[]>(
    []
  )
  const [collapsedGroups, setCollapsedGroups] = useState<Record<string, boolean>>({
    Today: false,
    Yesterday: false,
    'Last Week': false,
    'Last Month': false,
    Earlier: false
  })

  const [snackbarOpen, setSnackbarOpen] = useState(false)
  const [snackbarMessage, setSnackbarMessage] = useState('')

  const dispatch = useAppDispatch()

  const handleOpenASODesignClick = () => {
    const resWindow = window.open(
      '/#/aso_design',
      'ASO Design',
      'width=1200,height=800,left=200,top=200,titlebar=no,status=no,toolbar=no,menubar=no,location=no'
    )
    setCurrentWindow(resWindow)
  }

  const toggleGroupCollapse = (group: string) => {
    setCollapsedGroups((prev) => ({
      ...prev,
      [group]: !prev[group]
    }))
  }

  // useEffect(() => {
  //   try {
  //     // 构造测试数据
  //     const mockEntry = {
  //       timestamp: '06242025_1734',
  //       filename: 'aso_design_results_06242025_1734.tsv',
  //       serialized: JSON.stringify([
  //         {
  //           id: 'example1',
  //           status: 'successful',
  //           search: 'GTTTTTCTGA...',
  //           aso: 'AAAGGAACTG...',
  //           information: { warning: 'GC content failed' }
  //         }
  //       ])
  //     }

  //     const mockList = Array.from({ length: 50 }, (_, i) => ({
  //       ...mockEntry,
  //       timestamp: `06242025_173${i}`, // 1730, 1731, ..., 1739
  //       filename: `aso_design_results_06242025_173${i}.tsv`
  //     }))

  //     // 模拟去重逻辑（保留最新）
  //     const seen = new Set<string>()
  //     const deduped = mockList
  //       .sort((a, b) => (a.timestamp < b.timestamp ? 1 : -1))
  //       .filter((item) => {
  //         if (seen.has(item.timestamp)) return false
  //         seen.add(item.timestamp)
  //         return true
  //       })

  //     console.log('Deduped download history:', deduped)
  //     setDownloadHistory(deduped)
  //   } catch (e) {
  //     console.warn('Failed to load mock download history', e)
  //   }
  // }, [])

  useEffect(() => {
    try {
      const historyRaw = localStorage.getItem('aso_design_results_history')
      const parsed: typeof downloadHistory = historyRaw ? JSON.parse(historyRaw) : []

      // 去重逻辑：保留最新的 entry
      const seen = new Set<string>()
      const deduped = parsed
        .sort((a, b) => (a.timestamp < b.timestamp ? 1 : -1))
        .filter((item) => {
          if (seen.has(item.timestamp)) return false
          seen.add(item.timestamp)
          return true
        })

      console.log('Deduped download history:', deduped)
      setDownloadHistory(deduped)
    } catch (e) {
      console.warn('Failed to load download history', e)
    }
  }, [])

  const downloadFromLocalStorage = (item: { filename: string; serialized: string }) => {
    const results = JSON.parse(item.serialized)
    const header = ['ID', 'Search Sequence', 'ASO Sequence', 'Status', 'Description'].join('\t')
    const tsvContent = results
      .map((r: any) => {
        const desc = r.information?.warning || r.information?.error || ''
        return [r.id, r.search || '', r.aso || '', r.status, desc.replace(/\n/g, ' ')].join('\t')
      })
      .join('\n')

    const blob = new Blob([`${header}\n${tsvContent}`], {
      type: 'text/tab-separated-values'
    })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = item.filename
    a.click()
    URL.revokeObjectURL(url)

    // ✅ Snackbar 提示
    setSnackbarMessage(`Download: ${item.filename}`)
    setSnackbarOpen(true)
  }

  const parseTimestamp = (timestamp: string) => {
    const match = timestamp.match(/^(\d{2})(\d{2})(\d{4})_(\d{2})(\d{2})$/)
    if (!match) return dayjs('invalid')
    const [, MM, DD, YYYY, hh, mm] = match
    return dayjs(`${YYYY}-${MM}-${DD}T${hh}:${mm}`)
  }

  const groupHistory = () => {
    const groups: Record<string, typeof downloadHistory> = {
      Today: [],
      Yesterday: [],
      'Last Week': [],
      'Last Month': [],
      Earlier: []
    }
    const now = dayjs()
    downloadHistory.forEach((item) => {
      const t = parseTimestamp(item.timestamp)
      const diff = now.diff(t, 'day')
      if (diff === 0) groups.Today.push(item)
      else if (diff === 1) groups.Yesterday.push(item)
      else if (diff <= 7) groups['Last Week'].push(item)
      else if (diff <= 30) groups['Last Month'].push(item)
      else groups.Earlier.push(item)
    })
    return groups
  }

  const readableTime = (timestamp: string) => {
    const t = parseTimestamp(timestamp)
    return t.isValid() ? t.format('MMM D, YYYY HH:mm') : timestamp
  }

  const grouped = groupHistory()

  return (
    <ASODesignLeftSideWraaper>
      <AsideMenu name='ASO Design' />
      <Stack direction='column' sx={{ m: 1, minWidth: 120, width: '100%', pr: '15px', whiteSpace: 'nowrap' }}>
        <BaimoButton
          size='sm'
          variant='solid'
          onClick={handleOpenASODesignClick}
          startDecorator={<FolderOpenRounded />}
          sx={{
            whiteSpace: 'nowrap',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
            display: 'inline-flex'
          }}>
          Design ASO Sequence
        </BaimoButton>
      </Stack>

      {/* 历史记录列表 */}
      {/* 历史记录列表（统一样式） */}
      {downloadHistory.length > 0 && (
        <Box sx={{ px: 1, width: '100%', overflowY: 'auto', maxHeight: 'calc(100vh - 150px)' }}>
          <List size='sm' sx={{ '--ListItem-paddingY': '4px', '--ListItemDecorator-size': '1.25rem', p: 0 }}>
            {(['Today', 'Yesterday', 'Last Week', 'Last Month', 'Earlier'] as const).map((group) => {
              const items = grouped[group] ?? []
              if (items.length === 0) return null
              const isOpen = !collapsedGroups[group]

              return (
                <React.Fragment key={group}>
                  {/* 分组标题：可折叠 + 单行省略 + 右侧计数右对齐 */}
                  <Box
                    sx={{
                      px: 1,
                      py: 0.25,
                      display: 'flex',
                      alignItems: 'center',
                      gap: 0.25,
                      minHeight: GROUP_ROW_HEIGHT,
                      height: GROUP_ROW_HEIGHT
                    }}>
                    <IconButton
                      size='small'
                      onClick={() => toggleGroupCollapse(group)}
                      sx={{ mr: 0.25, p: 0.25 }}
                      aria-label={isOpen ? `Collapse ${group}` : `Expand ${group}`}>
                      {isOpen ? <ExpandMoreIcon fontSize='small' /> : <KeyboardArrowRightIcon fontSize='small' />}
                    </IconButton>

                    <Tooltip title={group} arrow enterDelay={250} placement='top'>
                      <Typography
                        noWrap
                        sx={{
                          px: 0.5,
                          py: 0.5,
                          fontSize: 12,
                          color: 'neutral.500',
                          textTransform: 'uppercase',
                          letterSpacing: 0.3,
                          userSelect: 'none',
                          flex: 1,
                          overflow: 'hidden',
                          textOverflow: 'ellipsis'
                        }}>
                        {group}
                      </Typography>
                    </Tooltip>

                    <Typography
                      component='span'
                      sx={{
                        fontSize: 12,
                        color: 'neutral.500',
                        minWidth: 24,
                        textAlign: 'right',
                        ml: 0.5,
                        flex: '0 0 auto'
                      }}>
                      {items.length}
                    </Typography>
                  </Box>

                  {/* 分组内容 */}
                  {isOpen &&
                    items.map((item, idx) => (
                      <React.Fragment key={item.timestamp}>
                        <ListItem
                          sx={{
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'space-between',
                            gap: 1,
                            py: 0.5,
                            pr: 0
                          }}>
                          <Tooltip title={item.filename} placement='top-start' arrow enterDelay={250}>
                            <Typography
                              level='body-xs'
                              sx={{ whiteSpace: 'nowrap', color: 'text.secondary', flexShrink: 0 }}>
                              {readableTime(item.timestamp)}
                            </Typography>
                          </Tooltip>

                          <Button
                            size='sm'
                            variant='soft'
                            color='neutral'
                            onClick={() => downloadFromLocalStorage(item)}
                            sx={{ minHeight: '0.5rem', fontSize: 11, px: 1, py: 0.25 }}>
                            <DownloadIcon fontSize='small' />
                          </Button>
                        </ListItem>
                        {idx !== items.length - 1 && <Divider sx={{ my: 0.5 }} />}
                      </React.Fragment>
                    ))}
                </React.Fragment>
              )
            })}
          </List>
        </Box>
      )}

      {!downloadHistory.length && (
        <Typography sx={{ padding: '10px 5px 10px 5px', color: '#707070', fontSize: '14px', textAlign: 'center' }}>
          No records <br /> Click the button to start designing ASO sequences.
        </Typography>
      )}

      {snackbarOpen && (
        <Snackbar
          open
          color='success'
          variant='outlined'
          autoHideDuration={3000}
          onClose={() => setSnackbarOpen(false)}
          anchorOrigin={{ vertical: 'top', horizontal: 'center' }}>
          <Box display='flex' alignItems='center' gap={1}>
            <CheckCircleRoundedIcon color='success' fontSize='small' />
            <strong>Downloaded:</strong> {snackbarMessage}
          </Box>
        </Snackbar>
      )}
    </ASODesignLeftSideWraaper>
  )
}

export default memo(ASODesign)
