import React, { memo, useEffect, useState } from 'react'
import type { FC, ReactNode } from 'react'
import type { DataNode } from 'antd/es/tree'
import { TagOutlined } from '@ant-design/icons'
import Tree from 'antd/es/tree'
import { PlusSquareOutlined, UnorderedListOutlined } from '@ant-design/icons'
import type { RadioChangeEvent } from 'antd'
import Tabs from '@mui/joy/Tabs'
import TabList from '@mui/joy/TabList'
import Tab from '@mui/joy/Tab'
import TabPanel from '@mui/joy/TabPanel'
import Stack from '@mui/joy/Stack'

// import { formatTitle } from '../home'
import AsideMenu from '../../aside-menu'
import { TrackWrapper } from './style'
import { shallowEqualApp, useAppSelecter } from '@/store'
import { Segmented } from 'antd'
import AddTrack from './c-cpns/add-track'
import TrackList from './c-cpns/track-list'
import { MacScrollbar } from 'mac-scrollbar'
import { Divider } from '@mui/joy'

interface Iprops {
  children?: ReactNode
}

interface ITreeData extends DataNode {
  info?: string
  name?: string
  key: string
}

type modeType = 'list' | 'add'

const Tracks: FC<Iprops> = () => {
  const [treeData, setTreeData] = useState<ITreeData[]>()
  const [defaultExpandedKeys, setDefaultExpandedKeys] = useState<string[]>([])
  const [isShowAddTrack, setIsShowAddTrack] = useState(false)
  const [mode, setMode] = useState<modeType>('add')

  const { trackListData } = useAppSelecter(
    (state) => ({
      trackListData: state.rbSettings.trackListData
    }),
    shallowEqualApp
  )

  function isEmptyObject(obj) {
    return Object.prototype.toString.call(obj) === '[object Object]' && Object.keys(obj).length === 0
  }

  useEffect(() => {
    if (trackListData === undefined || trackListData === '' || isEmptyObject(trackListData)) return
    const formatData = formatTreeData(trackListData)

    setTreeData(formatData)
    // const formatData = formatTreeData(res.data.results)
    console.log('Track formatData', trackListData)
  }, [trackListData])

  const formatTreeData = (data) => {
    const treeData: ITreeData[] = []
    const treeObj: any = {}
    const treeArr: any = []
    data.forEach((ele, i) => {
      console.log('formatTreeData', ele)
      const type = 'annotation'
      const { name, index } = ele
      // const chromName = chrom === undefined ? chr : 'chr' + chrom
      // const position = `${chromName}:${start}-${end}`
      // const title = trans_name === undefined ? position : trans_name

      // // two key for tree: trans_id and position, position is unique
      // // const key = trans_id === undefined ? position : trans_id
      // const key = position
      // const type = trans_type === undefined ? 'region' : trans_type

      // if (!i) treeArr.push(type)
      setDefaultExpandedKeys([type])

      if (type in treeObj) {
        treeObj[type].push({
          title: name,
          key: index,
          icon: <TagOutlined />
        })
      } else {
        treeObj[type] = [
          {
            title: name,
            key: index,
            icon: <TagOutlined />
          }
        ]
      }
    })

    for (const key in treeObj) {
      treeArr.push(key)
      treeData.push({
        // title: formatTitle(key),
        title: '',
        key: key,
        children: treeObj[key]
      })
    }

    console.log('treeData', treeData)

    return treeData
  }

  const onSelect = (selectedKeys, info) => {
    const selectKey = selectedKeys[0]
    const haveChildren = info.node.children === undefined ? false : true
    console.log('selectKey==>', haveChildren, selectedKeys, selectKey, info)
    // if (selectKey !== undefined && !haveChildren) dispatch(changeTargetRegionAction(selectKey))
  }

  return (
    <TrackWrapper>
      <AsideMenu name='Track' />
      <Stack spacing={0} sx={{ width: '100%' }}>
        <AddTrack />

        {!isEmptyObject(trackListData) && (
          <MacScrollbar suppressScrollX={true}>
            <TrackList trackListData={trackListData} />
          </MacScrollbar>
        )}
      </Stack>
    </TrackWrapper>
  )
}

export default memo(Tracks)
