import React, { memo, useEffect, useMemo, useState } from 'react'
import type { FC, ReactNode } from 'react'
import AsideMenu from '../../aside-menu'
import { shallowEqualApp, useAppDispatch, useAppSelecter } from '@/store'
import { setPlugins } from '@/store/modules/rna_browser_settings'
import { IPanelConf, panelConf } from '@/config/panel-conf'

import Box from '@mui/joy/Box'
import Typography from '@mui/joy/Typography'
import Button from '@mui/joy/Button'
import Avatar from '@mui/joy/Avatar'
import Divider from '@mui/joy/Divider'
import Input from '@mui/joy/Input'
import Tooltip from '@mui/material/Tooltip'

import List from '@mui/joy/List'
import ListItem from '@mui/joy/ListItem'
import IconButton from '@mui/material/IconButton'
import ExpandMoreIcon from '@mui/icons-material/ExpandMore'
import KeyboardArrowRightIcon from '@mui/icons-material/KeyboardArrowRight'
import SearchIcon from '@mui/icons-material/Search'
import CloseIcon from '@mui/icons-material/Close'
import CloudDownloadIcon from '@mui/icons-material/CloudDownload'
import StarIcon from '@mui/icons-material/Star'

interface Iprops {
  children?: ReactNode
}

const GROUP_ROW_HEIGHT = 26

const Plugin: FC<Iprops> = () => {
  const dispatch = useAppDispatch()
  const { plugins } = useAppSelecter(
    (state) => ({
      plugins: (state.rbSettings.plugins ?? []) as IPanelConf[]
    }),
    shallowEqualApp
  )

  // 初始化：如为空，用 panelConf 回填
  useEffect(() => {
    if (!plugins || plugins.length === 0) {
      dispatch(setPlugins(panelConf as any))
    }
  }, [])

  // —— 搜索（带去抖） ——
  const [query, setQuery] = useState('')
  const [debounced, setDebounced] = useState(query)
  useEffect(() => {
    const t = setTimeout(() => setDebounced(query.trim().toLowerCase()), 160)
    return () => clearTimeout(t)
  }, [query])

  const filtered = useMemo(() => {
    if (!debounced) return plugins
    return plugins.filter((p) => {
      const cands = [p.name, p.description, p.author]
        .filter(Boolean)
        .map(String)
        .map((s) => s.toLowerCase())
      return cands.some((s) => s.includes(debounced))
    })
  }, [plugins, debounced])

  // —— 分组：Pinned / Enabled / Disabled（默认都展开） ——
  const pinned = filtered.filter((p) => !!p.pin)
  const enabled = filtered.filter((p) => !!p.enable && !p.pin)
  const disabled = filtered.filter((p) => !p.enable && !p.pin)
  console.log('Plugin >> filtered >>> ', filtered)
  console.log('Plugin >> pinned >>> ', pinned)
  console.log('Plugin >> enabled >>> ', enabled)
  console.log('Plugin >> disabled >>> ', disabled)
  const groups = [
    { key: 'pinned', label: 'Pinned', items: pinned },
    { key: 'enabled', label: 'Enabled', items: enabled },
    { key: 'disabled', label: 'Disabled', items: disabled }
  ] as const

  const [expanded, setExpanded] = useState<Set<string>>(new Set(['pinned', 'enabled', 'disabled']))
  const toggle = (key: string) =>
    setExpanded((prev) => {
      const next = new Set(prev)
      next.has(key) ? next.delete(key) : next.add(key)
      return next
    })

  // —— 切换启用状态 ——
  const toggleEnable = (name: string) => {
    // 查找插件，如果是 pin 状态则不允许切换
    const plugin = plugins.find((p) => p.name === name)
    if (plugin?.pin) {
      return // 固定插件不允许切换状态
    }

    const next = plugins.map((p) => (p.name === name ? { ...p, enable: !p.enable } : p))
    dispatch(setPlugins(next as any))
  }

  return (
    <>
      <AsideMenu name='Plugin' />

      <Box
        sx={{
          position: 'sticky',
          top: 0,
          zIndex: 3,
          bgcolor: 'background.body',
          borderBottom: '1px solid',
          borderColor: 'divider',
          p: 1
        }}>
        <Input
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder='Search plugins (name, description, author)…'
          size='sm'
          startDecorator={<SearchIcon fontSize='small' />}
          endDecorator={
            query ? (
              <IconButton size='small' onClick={() => setQuery('')} sx={{ p: 0.25 }}>
                <CloseIcon fontSize='small' />
              </IconButton>
            ) : null
          }
          slotProps={{ input: { 'aria-label': 'Search plugins' } }}
        />
      </Box>

      {groups.map((g) => {
        const isOpen = expanded.has(g.key)
        if (g.items.length === 0) return null

        return (
          <React.Fragment key={g.key}>
            <Box
              sx={{
                px: 1,
                py: 0.25,
                display: 'flex',
                alignItems: 'center',
                gap: 0.25,
                minHeight: GROUP_ROW_HEIGHT,
                height: GROUP_ROW_HEIGHT
              }}>
              <IconButton size='small' onClick={() => toggle(g.key)} sx={{ mr: 0.25, p: 0.25 }}>
                {isOpen ? <ExpandMoreIcon fontSize='small' /> : <KeyboardArrowRightIcon fontSize='small' />}
              </IconButton>

              <Typography
                noWrap
                sx={{
                  px: 0.5,
                  py: 0.5,
                  fontSize: 12,
                  color: 'neutral.500',
                  textTransform: 'uppercase',
                  letterSpacing: 0.3,
                  userSelect: 'none',
                  flex: 1,
                  overflow: 'hidden',
                  textOverflow: 'ellipsis'
                }}>
                {g.label}
              </Typography>

              <Typography
                component='span'
                sx={{
                  fontSize: 12,
                  color: 'neutral.500',
                  minWidth: 24,
                  textAlign: 'right',
                  ml: 0.5,
                  flex: '0 0 auto'
                }}>
                {g.items.length}
              </Typography>
            </Box>

            {isOpen && (
              <List
                size='sm'
                sx={{
                  '--ListItem-paddingY': '4px',
                  '--ListItemDecorator-size': '1.25rem',
                  p: 0.5,
                  pt: 0,
                  pb: 0
                }}>
                {g.items.map((ext, index) => {
                  const primary = ext.name ?? 'Unnamed Plugin'
                  const secondary = ext.description ?? ''
                  const author = ext.author ?? ''

                  return (
                    <React.Fragment key={`${primary}-${index}`}>
                      {/* 保持你原来的 ListItem 风格 */}
                      <ListItem sx={{ alignItems: 'flex-start', gap: 1, paddingLeft: 0 }}>
                        <Box sx={{ display: 'flex', alignItems: 'flex-start', gap: 1 }}>
                          <Avatar size='sm' variant='soft'>
                            {ext.name.charAt(0).toUpperCase()}
                          </Avatar>
                          <Box
                            display='flex'
                            sx={{
                              flexDirection: 'column',
                              justifyContent: 'flex-start',
                              gap: 0
                            }}>
                            <Typography
                              level='title-sm'
                              sx={{
                                maxWidth: 170,
                                fontSize: '12px',
                                fontWeight: 600,
                                color: '#000000',
                                marginTop: '5px',
                                textOverflow: 'ellipsis',
                                whiteSpace: 'nowrap'
                              }}>
                              {ext.name}
                            </Typography>
                            <Typography
                              level='body-sm'
                              noWrap
                              mt={0.5}
                              sx={{
                                maxWidth: 170,
                                fontSize: '12px',
                                overflow: 'hidden',
                                textOverflow: 'ellipsis',
                                whiteSpace: 'nowrap'
                              }}>
                              {ext.description}
                            </Typography>
                            <Box display='flex' alignItems='center' justifyContent='space-between'>
                              <Typography level='body-xs' color='neutral'>
                                {ext.author}
                              </Typography>
                              {ext.pin ? (
                                <Tooltip
                                  title='This plugin is pinned and cannot be disabled'
                                  placement='bottom-end'
                                  arrow>
                                  <span>
                                    <Button
                                      size='sm'
                                      variant='soft'
                                      color='neutral'
                                      disabled
                                      sx={{
                                        paddingTop: '5px',
                                        minHeight: '0.5rem',
                                        fontSize: '11px',
                                        paddingBlock: '0.1rem',
                                        paddingInline: '0.5rem',
                                        opacity: 1,
                                        cursor: 'not-allowed'
                                      }}>
                                      Pinned
                                    </Button>
                                  </span>
                                </Tooltip>
                              ) : (
                                <Button
                                  size='sm'
                                  variant='soft'
                                  color={ext.enable ? 'warning' : 'success'}
                                  onClick={() => toggleEnable(ext.name)}
                                  sx={{
                                    paddingTop: '5px',
                                    minHeight: '0.5rem',
                                    fontSize: '11px',
                                    paddingBlock: '0.1rem',
                                    paddingInline: '0.5rem'
                                  }}>
                                  {ext.enable ? 'Disabled' : 'Enabled'}
                                </Button>
                              )}
                            </Box>
                          </Box>
                        </Box>
                      </ListItem>
                      {index < g.items.length - 1 && <Divider />}
                    </React.Fragment>
                  )
                })}
              </List>
            )}
          </React.Fragment>
        )
      })}

      {/* 空态 */}
      {filtered.length === 0 && (
        <Typography sx={{ p: '10px 5px', color: '#707070', textAlign: 'center', fontSize: 14 }}>No matches</Typography>
      )}
    </>
  )
}

export default memo(Plugin)
