import React, { memo, useEffect, useRef, useState, useMemo } from 'react'
import type { FC, ReactNode } from 'react'
import { useAppDispatch, useAppSelecter } from '@/store'
import AsideMenu from '@/views/main/c-cpns/left-asider/c-cpns/index'
import { HistoryWraaper } from './style'

import { Box, Typography, CircularProgress, Input } from '@mui/joy'
import List from '@mui/material/List'
import ListItemButton from '@mui/material/ListItemButton'
import ListItemText from '@mui/material/ListItemText'
import Divider from '@mui/material/Divider'
import Tooltip from '@mui/material/Tooltip'
import IconButton from '@mui/material/IconButton'
import ExpandMoreIcon from '@mui/icons-material/ExpandMore'
import KeyboardArrowRightIcon from '@mui/icons-material/KeyboardArrowRight'
import SearchIcon from '@mui/icons-material/Search'
import CloseIcon from '@mui/icons-material/Close'

import { setCurrentRegion, IRBRegion } from '@/store/modules/rna_browser_settings'
import { TRANS_TYPE_META } from '@/constants/transType'

import type { HistoryGroup } from '@/utils/formatHistoryAsync'
import { formatTreeDataAsync } from '@/utils/formatHistoryAsync'

interface Iprops {
  children?: ReactNode
}

/** --- TransType 徽标 --- */
const TransTypeBadge: React.FC<{ transType?: string; size?: number }> = ({ transType, size = 18 }) => {
  const key = transType ?? ''
  const meta = TRANS_TYPE_META[key] ?? { color: '#9e9e9e', label: 'OT' }
  const fullName = (transType && transType.replace(/_/g, ' ')) || 'other'
  return (
    <Tooltip title={fullName} arrow enterDelay={250} placement='right'>
      <Box
        component='span'
        role='img'
        aria-label={fullName}
        sx={{
          width: size,
          height: size,
          display: 'inline-flex',
          alignItems: 'center',
          justifyContent: 'center',
          borderRadius: '3px',
          backgroundColor: meta.color,
          color: '#fff',
          fontSize: size <= 18 ? 10 : 11,
          fontWeight: 700,
          lineHeight: 1,
          flex: '0 0 auto',
          userSelect: 'none',
          mr: 0.75
        }}>
        {meta.label}
      </Box>
    </Tooltip>
  )
}

/** --- 名称工具 --- */
function baseName(r: IRBRegion): string {
  return (
    r.trans_name ??
    r.trans_id ??
    r.gene_name ??
    r.gene_id ??
    r.search ??
    (r.chr ? `${r.chr}:${r.start}-${r.end}` : 'unknown')
  ).toString()
}
function displayName(r: IRBRegion): string {
  const n = baseName(r)
  return r.offset !== undefined ? `${n}:${r.offset}` : n
}

const History: FC<Iprops> = () => {
  const dispatch = useAppDispatch()
  const { historyRegions } = useAppSelecter((state) => ({
    historyRegions: state.rbSettings.historyRegions as IRBRegion[] | undefined
  }))

  const [loading, setLoading] = useState(false)
  const [groups, setGroups] = useState<HistoryGroup[]>([])
  const seqRef = useRef(0)

  useEffect(() => {
    let alive = true
    const mySeq = ++seqRef.current
    setLoading(true)
    ;(async () => {
      try {
        const result = await formatTreeDataAsync(historyRegions, { chunkSize: 1200, yieldWithIdle: true })
        if (alive && mySeq === seqRef.current) setGroups(result)
      } finally {
        if (alive && mySeq === seqRef.current) setLoading(false)
      }
    })()
    return () => {
      alive = false
    }
  }, [historyRegions])

  /** 折叠：默认 Today 展开（无 Today 则展开第一个） */
  const [expanded, setExpanded] = useState<Set<string>>(new Set(['Today']))
  useEffect(() => {
    if (groups.length === 0) return
    setExpanded((prev) => {
      if (prev.size > 0) return prev
      const hasToday = groups.some((g) => g.label === 'Today')
      return new Set(hasToday ? ['Today'] : [groups[0].label])
    })
  }, [groups])

  const toggleGroup = (label: string) => {
    setExpanded((prev) => {
      const next = new Set(prev)
      if (next.has(label)) next.delete(label)
      else next.add(label)
      return next
    })
  }

  /** 高度适配 */
  const [maxHeight, setMaxHeight] = useState<number>(window.innerHeight - 85)
  useEffect(() => {
    const onResize = () => setMaxHeight(window.innerHeight - 85)
    window.addEventListener('resize', onResize)
    return () => window.removeEventListener('resize', onResize)
  }, [])

  const handleSelectedClick = (r: IRBRegion) => dispatch(setCurrentRegion(r))

  /** ------- 搜索框状态 & 去抖 ------- */
  const [query, setQuery] = useState('')
  const [debounced, setDebounced] = useState(query)
  useEffect(() => {
    const t = setTimeout(() => setDebounced(query.trim()), 180)
    return () => clearTimeout(t)
  }, [query])

  /** ------- 过滤逻辑：按 displayName、trans_id、gene_id、gene_name、chr:start-end 匹配 ------- */
  const filteredGroups = useMemo<HistoryGroup[]>(() => {
    const q = debounced.toLowerCase()
    if (!q) return groups

    const matches = (r: IRBRegion) => {
      const candidates = [
        displayName(r),
        r.trans_id,
        r.trans_name,
        r.gene_id,
        r.gene_name,
        r.search,
        r.chr && r.start != null && r.end != null ? `${r.chr}:${r.start}-${r.end}` : ''
      ]
        .filter(Boolean)
        .map(String)
      return candidates.some((s) => s.toLowerCase().includes(q))
    }

    const out: HistoryGroup[] = []
    for (const g of groups) {
      const items = g.items.filter((rec) => matches(rec.region))
      if (items.length) out.push({ ...g, items })
    }
    return out
  }, [groups, debounced])

  useEffect(() => {
    if (!debounced) {
      if (groups.length > 0) {
        const hasToday = groups.some((g) => g.label === 'Today')
        setExpanded(new Set(hasToday ? ['Today'] : [groups[0].label]))
      } else {
        setExpanded(new Set())
      }
      return
    }

    const labels = filteredGroups.map((g) => g.label)
    setExpanded(new Set(labels))
  }, [debounced, filteredGroups, groups])

  return (
    <HistoryWraaper>
      <AsideMenu name='History' />
      <div className='content' style={{ height: maxHeight, flex: 1, overflowY: 'auto', position: 'relative' }}>
        {/* 顶部搜索框（吸顶） */}
        <Box
          sx={{
            position: 'sticky',
            top: 0,
            zIndex: 3,
            bgcolor: 'background.body',
            borderBottom: '1px solid',
            borderColor: 'divider',
            p: 1
          }}>
          <Input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder='Search history (name, id, gene, chr:start-end, offset)…'
            size='sm'
            startDecorator={<SearchIcon fontSize='small' />}
            endDecorator={
              query ? (
                <IconButton size='small' onClick={() => setQuery('')} sx={{ p: 0.25 }}>
                  <CloseIcon fontSize='small' />
                </IconButton>
              ) : null
            }
            slotProps={{ input: { 'aria-label': 'Search history' } }}
          />
        </Box>

        {/* Loading 遮罩 */}
        {loading && (
          <Box
            sx={{
              position: 'absolute',
              inset: 0,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              backgroundColor: 'rgba(255,255,255,0.6)',
              zIndex: 2
            }}>
            <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 1 }}>
              <CircularProgress size='sm' />
              <Typography level='body-sm' color='neutral'>
                Loading history…
              </Typography>
            </Box>
          </Box>
        )}

        {/* 列表内容 */}
        {!loading && filteredGroups.length > 0 ? (
          <List dense disablePadding>
            {filteredGroups.map((g) => {
              const isOpen = expanded.has(g.label)
              return (
                <React.Fragment key={`${g.label}-${g.sortTime}`}>
                  {/* 组标题（可折叠） */}
                  <Box sx={{ px: 1, py: 0.25, display: 'flex', alignItems: 'center', gap: 0.25 }}>
                    <IconButton
                      size='small'
                      onClick={() => toggleGroup(g.label)}
                      sx={{ mr: 0.25, p: 0.25 }}
                      aria-label={(expanded.has(g.label) ? 'Collapse ' : 'Expand ') + g.label}>
                      {expanded.has(g.label) ? (
                        <ExpandMoreIcon fontSize='small' />
                      ) : (
                        <KeyboardArrowRightIcon fontSize='small' />
                      )}
                    </IconButton>

                    {/* Label：单行省略 + 悬浮显示完整内容；占满中间，让数字被顶到最右侧 */}
                    <Typography
                      noWrap
                      sx={{
                        px: 0.5,
                        py: 0.5,
                        fontSize: 12,
                        color: 'neutral.500',
                        textTransform: 'uppercase',
                        letterSpacing: 0.3,
                        userSelect: 'none',
                        flex: 1, // 关键：占满剩余空间，把计数推到右边
                        overflow: 'hidden',
                        textOverflow: 'ellipsis'
                      }}>
                      {g.label}
                    </Typography>

                    {/* 右侧计数：右对齐 */}
                    <Typography
                      component='span'
                      sx={{
                        fontSize: 12,
                        color: 'neutral.500',
                        fontWeight: 500,
                        minWidth: 24, // 给个最小宽度，避免抖动
                        textAlign: 'right', // 右对齐
                        ml: 0.5,
                        flex: '0 0 auto'
                      }}>
                      {g.items.length}
                    </Typography>
                  </Box>

                  {/* 组内容 */}
                  {isOpen &&
                    g.items.map((rec, i) => {
                      const r = rec.region
                      const primary = displayName(r)
                      const key = r.id ?? `${primary}-${rec.time}-${i}`
                      return (
                        <ListItemButton
                          key={key}
                          dense
                          onClick={() => handleSelectedClick(r)}
                          sx={{ pr: '5px', gap: 0, alignItems: 'center' }}>
                          <TransTypeBadge transType={r.trans_type} />

                          <ListItemText
                            primary={primary}
                            secondary={rec.trans_id ?? ''}
                            primaryTypographyProps={{ fontSize: 12 }}
                            secondaryTypographyProps={{ fontSize: 7, color: 'text.disabled' }}
                            sx={{
                              pl: '5px',
                              m: 0,
                              whiteSpace: 'nowrap',
                              overflow: 'hidden',
                              textOverflow: 'ellipsis'
                            }}
                          />
                        </ListItemButton>
                      )
                    })}
                  <Divider sx={{ my: 0.5 }} />
                </React.Fragment>
              )
            })}
          </List>
        ) : null}

        {/* 空态 */}
        {!loading && filteredGroups.length === 0 && (
          <Typography sx={{ p: '10px 5px', color: '#707070', fontSize: 14, textAlign: 'center' }}>
            {debounced ? 'No matches' : 'No records'} <br />
            {debounced ? 'Try another keyword.' : 'The search history will be automatically recorded here in RBrowser.'}
          </Typography>
        )}
      </div>
    </HistoryWraaper>
  )
}

export default memo(History)
