import React, { memo, useState, useEffect, useRef } from 'react'
import type { FC, ReactNode } from 'react'
import Button from '@mui/joy/Button'
import FormControl from '@mui/joy/FormControl'
import FormLabel from '@mui/joy/FormLabel'
import Input from '@mui/joy/Input'
import Modal from '@mui/joy/Modal'
import ModalDialog from '@mui/joy/ModalDialog'
import DialogTitle from '@mui/joy/DialogTitle'
import DialogContent from '@mui/joy/DialogContent'
import Stack from '@mui/joy/Stack'
import { DialogActions, Typography } from '@mui/joy'
import CheckCircleIcon from '@mui/icons-material/CheckCircle'
import ErrorOutlineIcon from '@mui/icons-material/ErrorOutline'
import CircularProgress from '@mui/material/CircularProgress'
import { useAppDispatch } from '@/store'
import { addChannelNewData } from '@/store/modules/rna_browser_settings'

interface Iprops {
  children?: ReactNode
  isOpen: boolean
  onClose: () => void
}

const SUPPORTED_EXTS = [
  'bw',
  'bb',
  'bigwig',
  'bigbed',
  'fa',
  'fasta',
  'fna',
  'bed',
  'bed.gz',
  'vcf',
  'vcf.gz',
  'gff',
  'gff.gz',
  'gtf',
  'gtf.gz',
  'gff3'
]

const mapExtToFormat: Record<string, string> = {
  bw: 'bigwig',
  bigwig: 'bigwig',
  bb: 'bigbed',
  bigbed: 'bigbed',
  fa: 'fasta',
  fasta: 'fasta',
  fna: 'fasta',
  bed: 'bed',
  'bed.gz': 'bed',
  vcf: 'vcf',
  'vcf.gz': 'vcf',
  gff: 'gff',
  'gff.gz': 'gff',
  gff3: 'gff3',
  gtf: 'gtf',
  'gtf.gz': 'gtf'
}

const RemoteTrack: FC<Iprops> = (props) => {
  const { isOpen, onClose } = props
  const dispatch = useAppDispatch()

  const [trackName, setTrackName] = useState<string>('')
  const [trackUrl, setTrackUrl] = useState<string>('')
  const [indexUrl, setIndexUrl] = useState<string>('')
  const [isIndexRequired, setIsIndexRequired] = useState<boolean>(false)

  // validation UI state
  const [isValidLocal, setIsValidLocal] = useState<boolean>(false) // quick local extension check
  const [isChecking, setIsChecking] = useState<boolean>(false) // async check in progress
  const [isAccessible, setIsAccessible] = useState<boolean | null>(null) // null = unknown
  const [error, setError] = useState<boolean>(false)
  const [errorMsg, setErrorMsg] = useState<string>('')

  const [indexError, setIndexError] = useState<string>('')

  const debounceTimer = useRef<number | null>(null)

  useEffect(() => {
    return () => {
      if (debounceTimer.current) {
        window.clearTimeout(debounceTimer.current)
      }
    }
  }, [])

  const handleTrackName = (e: any) => {
    setTrackName(e.target.value)
  }

  const detectExtAndIndexRequirement = (path: string) => {
    const lastSeg = (path || '').split('/').filter(Boolean).pop() || ''
    const lower = lastSeg.toLowerCase()
    // match double extension first (these require index)
    if (lower.endsWith('.bed.gz')) return { ext: 'bed.gz', requiresIndex: true }
    if (lower.endsWith('.vcf.gz')) return { ext: 'vcf.gz', requiresIndex: true }
    if (lower.endsWith('.gff.gz')) return { ext: 'gff.gz', requiresIndex: true }
    if (lower.endsWith('.gtf.gz')) return { ext: 'gtf.gz', requiresIndex: true }
    // single extension
    const parts = lower.split('.')
    const ext = parts.length > 1 ? parts[parts.length - 1] : ''
    return { ext, requiresIndex: false }
  }

  const validateInput = (input: string) => {
    try {
      const url = new URL(input)
      const { ext } = detectExtAndIndexRequirement(url.pathname || url.href)
      return SUPPORTED_EXTS.includes(ext)
    } catch {
      return false
    }
  }

  const validateRemoteTrack = async (
    input: string
  ): Promise<{ ok: boolean; format?: string; requiresIndex?: boolean }> => {
    try {
      const url = new URL(input)
      const { ext, requiresIndex } = detectExtAndIndexRequirement(url.pathname || url.href)
      const format = mapExtToFormat[ext]
      if (!format) return { ok: false, requiresIndex, format: undefined }

      try {
        // try HEAD
        const resp = await fetch(input, { method: 'HEAD' })
        if (resp.ok) return { ok: true, format, requiresIndex }
        // fallback to GET range
        const resp2 = await fetch(input, {
          method: 'GET',
          headers: { Range: 'bytes=0-0' }
        })
        if (resp2.ok) return { ok: true, format, requiresIndex }
        return { ok: false, format, requiresIndex }
      } catch (err) {
        // network/CORS issues: return known format but ok=false
        return { ok: false, format, requiresIndex }
      }
    } catch (e) {
      return { ok: false }
    }
  }

  const handleRemoteURL = (e: any) => {
    const val = e.target.value.trim()
    setTrackUrl(val)
    setError(false)
    setErrorMsg('')
    setIndexError('')
    setIndexUrl('')

    const okLocal = validateInput(val)
    setIsValidLocal(okLocal)
    setIsAccessible(null)

    // detect if index is required and set state early
    try {
      const url = new URL(val)
      const { ext, requiresIndex } = detectExtAndIndexRequirement(url.pathname || url.href)
      setIsIndexRequired(!!requiresIndex)
      // if requiresIndex reset index states
      if (!requiresIndex) {
        setIndexUrl('')
        setIndexError('')
      }
    } catch {
      setIsIndexRequired(false)
    }

    if (debounceTimer.current) {
      window.clearTimeout(debounceTimer.current)
      debounceTimer.current = null
    }

    if (!okLocal) {
      setIsChecking(false)
      setIsAccessible(false)
      setError(true)
      setErrorMsg(
        'Please enter an http(s) URL ending with a supported extension (e.g. .bw .bb .bigwig .bigbed .bed .bed.gz .vcf .vcf.gz .gff .gff.gz .gtf .gtf.gz .fa .fasta)'
      )
      return
    }

    setIsChecking(true)
    debounceTimer.current = window.setTimeout(async () => {
      try {
        const res = await validateRemoteTrack(val)
        setIsAccessible(!!(res.ok && res.format))
        setError(!(res.ok && res.format))
        if (!res.format) {
          setErrorMsg(
            'Unsupported file format. Supported: .bw .bb .bigwig .bigbed .bed .bed.gz .vcf .vcf.gz .gff .gff.gz .gtf .gtf.gz .fa .fasta'
          )
        } else if (!res.ok) {
          setErrorMsg('Cannot access the file URL. Please check network or CORS settings.')
        } else {
          setErrorMsg('')
        }
        // ensure index requirement matches server-detected info
        if (res.requiresIndex !== undefined) setIsIndexRequired(!!res.requiresIndex)
      } catch {
        setIsAccessible(false)
        setError(true)
        setErrorMsg('Validation failed: cannot access URL or CORS blocked')
      } finally {
        setIsChecking(false)
      }
    }, 400)
  }

  const handleIndexURLChange = (e: any) => {
    const v = e.target.value.trim()
    setIndexUrl(v)
    setIndexError('')
    // quick local check: must end with .tbi
    if (v && !/\.tbi$/i.test(v)) {
      setIndexError('Index URL should end with .tbi')
    }
  }

  const derivePlotFromFormat = (format?: string) => {
    // mapping per request:
    // bigwig -> 'bar'
    // bigbed, bed, vcf -> 'rect'
    // gff, gff3, gtf -> 'gff'
    if (!format) return 'rect'
    const f = format.toLowerCase()
    if (f === 'bigwig') return 'bar'
    if (f === 'bigbed') return 'rect'
    if (f === 'bed') return 'rect'
    if (f === 'vcf') return 'rect'
    if (f === 'gff' || f === 'gff3' || f === 'gtf') return 'gff'
    // fallback
    return 'rect'
  }

  const handleRemoteTrackSubmit = async () => {
    setError(false)
    setErrorMsg('')
    setIndexError('')

    // final validation for main file
    const res = await validateRemoteTrack(trackUrl)
    if (!res.format) {
      setError(true)
      setErrorMsg(
        'Unsupported file format. Supported: .bw .bb .bigwig .bigbed .bed .bed.gz .vcf .vcf.gz .gff .gff.gz .gtf .gtf.gz .fa .fasta'
      )
      return
    }
    if (!res.ok) {
      setError(true)
      setErrorMsg('Cannot access the file URL. Please check network or CORS settings.')
      return
    }

    // if index required, ensure indexUrl provided and looks valid
    if (res.requiresIndex || isIndexRequired) {
      if (!indexUrl) {
        setIndexError('Index file URL is required for compressed files (.bed.gz / .vcf.gz / .gff.gz / .gtf.gz)')
        return
      }
      if (!/\.tbi$/i.test(indexUrl)) {
        setIndexError('Index URL should end with .tbi')
        return
      }
    }

    const plot = derivePlotFromFormat(res.format)

    const trackSettings = [
      {
        name: trackName || extractNameFromUrl(trackUrl),
        index: indexUrl || '',
        plot,
        method: 'remote',
        format: res.format,
        url: trackUrl
      }
    ]
    dispatch(addChannelNewData(trackSettings))
    onClose()
  }

  const extractNameFromUrl = (u: string) => {
    try {
      const last = new URL(u).pathname.split('/').filter(Boolean).pop() || u
      // remove gz extension if present
      return last.replace(/(\.bed\.gz|\.vcf\.gz|\.gff\.gz|\.gtf\.gz|\.gz)$/i, '')
    } catch {
      return ''
    }
  }

  const handleExample = () => {
    setTrackName('Example track')
    setTrackUrl('https://data.rbrowser.org/datahub/merip/caRNA_MeRIP-seq/IP/1..GM18499..caRNA_MeRIP_IP.bw')
    setIsIndexRequired(false)
    setIndexUrl('')
    setError(false)
    setErrorMsg('')
    setIndexError('')
  }

  return (
    <div>
      <Modal open={isOpen} onClose={onClose}>
        <ModalDialog sx={{ width: 800, maxWidth: '95vw', py: 2 }}>
          <DialogTitle>Create new remote track</DialogTitle>
          <DialogContent>Fill in the information of the remote track.</DialogContent>
          <Stack spacing={2}>
            <FormControl>
              <FormLabel>Track name</FormLabel>
              <Input
                name='trackName'
                placeholder='Enter track name (optional)'
                autoFocus
                value={trackName}
                onChange={handleTrackName}
              />
            </FormControl>

            <FormControl>
              <FormLabel>Remote File URL</FormLabel>
              <Input
                type='url'
                name='trackUrl'
                placeholder='Input remote URL (http(s)://...)'
                required
                value={trackUrl}
                onChange={handleRemoteURL}
                endDecorator={
                  isChecking ? (
                    <CircularProgress size={18} />
                  ) : isAccessible ? (
                    <CheckCircleIcon color='success' />
                  ) : isValidLocal ? (
                    <ErrorOutlineIcon color='warning' />
                  ) : (
                    error && <ErrorOutlineIcon color='error' />
                  )
                }
                aria-describedby='track-url-helper'
              />
              <Typography
                id='track-url-helper'
                level='body-sm'
                sx={{ mt: 0.5, color: error ? 'danger.500' : 'text.secondary' }}>
                {isChecking
                  ? 'Validating URL accessibility…'
                  : errorMsg ||
                    'Supported formats: .bw .bb .bigwig .bigbed .bed .bed.gz .vcf .vcf.gz .gff .gff.gz .gtf .gtf.gz .fa .fasta (auto-detected)'}
              </Typography>
            </FormControl>

            {isIndexRequired && (
              <FormControl>
                <FormLabel>Remote File Index URL</FormLabel>
                <Input
                  type='url'
                  name='indexUrl'
                  placeholder='If required, input index URL (must end with .tbi)'
                  value={indexUrl}
                  onChange={handleIndexURLChange}
                  endDecorator={
                    indexError ? (
                      <ErrorOutlineIcon color='error' />
                    ) : indexUrl ? (
                      <CheckCircleIcon color='success' />
                    ) : null
                  }
                  aria-describedby='track-index-helper'
                />
                <Typography
                  id='track-index-helper'
                  level='body-sm'
                  sx={{ mt: 0.5, color: indexError ? 'danger.500' : 'text.secondary' }}>
                  {indexError ||
                    'Index required for compressed files (.bed.gz, .vcf.gz, .gff.gz, .gtf.gz). Index file should end with .tbi'}
                </Typography>
              </FormControl>
            )}

            <DialogActions>
              <Button variant='soft' onClick={handleRemoteTrackSubmit} disabled={isChecking}>
                Submit
              </Button>
              <Button variant='soft' color='success' onClick={handleExample}>
                Example
              </Button>
              <Button variant='plain' color='neutral' onClick={onClose}>
                Cancel
              </Button>
            </DialogActions>
          </Stack>
        </ModalDialog>
      </Modal>
    </div>
  )
}

export default memo(RemoteTrack)
