import React, { memo, useEffect, useState } from 'react'
import type { FC, ReactNode } from 'react'
import { useAppDispatch, useAppSelecter } from '@/store'
import AsideMenu from '@/views/main/c-cpns/left-asider/c-cpns/index'
import { DataNode } from 'antd/es/tree'
import Tree from 'antd/es/tree'

import { TagOutlined } from '@ant-design/icons'
import Button from '@mui/joy/Button'
import Modal from '@mui/joy/Modal'
import ModalDialog from '@mui/joy/ModalDialog'
import { DataHubLeftSideWraaper } from './style'
import { nanoid } from 'nanoid'
import { changeTargetRegionAction, fetchTargetRegionAction } from '@/store/modules/rna-browser'
import { regionString2Obj } from '@/assets/utils/base'
import List from '@mui/joy/List'
import ListItem from '@mui/joy/ListItem'
import ListSubheader from '@mui/joy/ListSubheader'
import ListItemButton from '@mui/joy/ListItemButton'
import Sheet from '@mui/joy/Sheet'

import FolderOpenRounded from '@mui/icons-material/FolderOpenRounded'
import ClearRounded from '@mui/icons-material/ClearRounded'
import { Box, Chip, ChipDelete, Stack } from '@mui/joy'
import loadedDataHubTrackList from '../../loaded-tracks'
import TrackList from '../track/c-cpns/track-list/index'
import { addChannelNewData } from '@/store/modules/rna_browser_settings'
import BaimoButton from '@/components/button'

interface Iprops {
  children?: ReactNode
}

const DataHub: FC<Iprops> = () => {
  const [currentWindow, setCurrentWindow] = useState<Window | null>(null)
  const [selectorData, setSelectorData] = useState<any>([])
  const isApplication = import.meta.env.VITE_IS_APPLICATION === 'true'
  const [showType, setShowType] = useState<'new' | 'modal' | 'newTab'>(isApplication ? 'newTab' : 'new')
  const [modalOpen, setModalOpen] = useState(false)

  const dispatch = useAppDispatch()

  const handleOpenDataHubClick = () => {
    console.log('handleOpenDataHubClick', showType)
    const fullUrl = window.location.origin + window.location.pathname + '#/data_hub'
    if (showType === 'new') {
      const resWindow = window.open(
        fullUrl,
        'DataHub',
        'width=1200,height=800,left=200,top=200,titlebar=no,status=no,toolbar=no,menubar=no,location=no'
      )
      setCurrentWindow(resWindow)
    } else if (showType === 'newTab') {
      window.open(fullUrl, '_blank')
    } else {
      setModalOpen(true)
    }
  }

  const handleCloseModal = () => {
    setModalOpen(false)
  }

  const toggleShowType = () => {
    setShowType((s) => (s === 'new' ? 'modal' : 'new'))
  }

  const handleAddTestDataClick = () => {
    console.log('handleAddTestDataClick')
    const testData = [
      {
        name: 'GRCh38-cCREs',
        plot: 'bar',
        data: {
          method: 'remote',
          format: 'bigbed',
          url: 'https://data.rbrowser.org/channels/epigenome/GRCh38-cCREs.bigBed'
        }
      },
      {
        name: 'SINE (Repeats)',
        plot: 'rect',
        level: 'rna',
        data: {
          method: 'remote',
          format: 'bed',
          url: 'https://data.rbrowser.org/datahub/rna_reference/Homo_sapiens/bed/SINE.bed.gz',
          index: 'https://data.rbrowser.org/datahub/rna_reference/Homo_sapiens/bed/SINE.bed.gz.tbi'
        }
      }
    ]
    const trackSettings: any[] = []
    testData.forEach((item) => {
      const {
        name,
        data: { format, url, index = '' }
      } = item

      trackSettings.push({
        name: `${name}`,
        fileIndex: index,
        method: 'remote',
        format: format,
        url: url
      })
    })

    console.log(' gs', trackSettings)
    dispatch(addChannelNewData(trackSettings))
  }

  // const handleClearAllClick = () => {
  //   setSelectorData([])
  //   localStorage.removeItem('selectorData')
  // }

  // Storage event listener moved to transcript/index.tsx for global handling
  // This ensures it works even when the left sidebar DataHub tab is not open

  // 监听来自内嵌页面（iframe）的 postMessage：当收到 { type: 'datahub:apply' } 时关闭 modal
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      const payload = event.data
      // 支持直接对象或 JSON 字符串
      let data
      if (typeof payload === 'string') {
        try {
          data = JSON.parse(payload)
        } catch {
          data = payload
        }
      } else {
        data = payload
      }

      if (data && data.type === 'datahub:apply') {
        setModalOpen(false)
      }
    }

    window.addEventListener('message', handleMessage)
    return () => window.removeEventListener('message', handleMessage)
  }, [])

  return (
    <DataHubLeftSideWraaper>
      <AsideMenu name='DataHub' />
      <Stack
        direction='column'
        spacing={1}
        sx={{ m: 1, minWidth: 120, width: '100%', pr: '15px', whiteSpace: 'nowrap' }}
        // sx={{
        //   display: 'flex',
        //   justifyContent: 'center',
        //   alignItems: 'center',
        //   width: '100%',
        //   padding: '10px 0',
        //   gap: '10px'
        // }}
      >
        <BaimoButton
          size='sm'
          variant='solid'
          onClick={handleOpenDataHubClick}
          startDecorator={<FolderOpenRounded />}
          sx={{
            whiteSpace: 'nowrap',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
            display: 'inline-flex'
          }}>
          Open DataHub
        </BaimoButton>
      </Stack>

      {/* <Stack
        direction='row'
        sx={{
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          width: '100%',
          padding: '10px 0',
          gap: '10px'
        }}>
        <Button
          size='sm'
          variant='soft'
          onClick={handleAddTestDataClick}
          startDecorator={<FolderOpenRounded />}
          sx={{
            whiteSpace: 'nowrap',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
            display: 'inline-flex',
            justifyContent: 'flex-start'
          }}>
          Add Test Data
        </Button>
      </Stack> */}

      <Modal open={modalOpen} onClose={handleCloseModal}>
        <ModalDialog
          variant='outlined'
          sx={{
            width: 'calc(100vw - 80px)',
            height: 'calc(100vh - 80px)',
            p: 0,
            overflow: 'hidden',
            display: 'flex',
            flexDirection: 'column'
          }}>
          <Box component='div' sx={{ flex: 1, overflow: 'hidden' }}>
            <iframe title='DataHub' src={'/#/data_hub'} style={{ width: '100%', height: '100%', border: '0' }} />
          </Box>
        </ModalDialog>
      </Modal>

      <Sheet
        variant='outlined'
        sx={{
          width: '100%',
          height: window.innerHeight - 140,
          overflowY: 'auto',
          overflowX: 'hidden',
          border: 'none',
          borderRadius: '0'
        }}>
        {/* TODO: more settings */}
      </Sheet>
    </DataHubLeftSideWraaper>
  )
}

export default memo(DataHub)
