// src/utils/formatHistoryAsync.ts
export type IRBRegion = {
  chr: string
  start: number
  end: number
  id?: string
  offset?: number
  time?: number
  strand?: string
  search?: string
  trans_id?: string
  trans_name?: string
  trans_type?: string
  gene_id?: string
  gene_name?: string
  gene_type?: string
  favoriteCategory?: string
  by?: string
  level?: 'RNA' | 'DNA' | 'PROTEIN' | 'GENE' | 'CDS'
}

export type HistoryRecord = {
  id: string
  time: number
  trans_id?: string
  trans_name?: string
  trans_type?: string
  region: IRBRegion
  [k: string]: any
}

export type HistoryGroup = {
  label: string
  sortTime: number
  items: HistoryRecord[]
}

const MONTHS = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'] as const
const DAY_MS = 24 * 60 * 60 * 1000

function startOfDay(ts: number) {
  const d = new Date(ts)
  d.setHours(0, 0, 0, 0)
  return +d
}

function formatTimeLabel(ts: number): string {
  if (!ts || Number.isNaN(ts)) return 'Unknown'
  const now = Date.now()
  const d0 = startOfDay(now)
  const d1 = startOfDay(ts)
  const diffDays = Math.floor((d0 - d1) / DAY_MS)
  if (diffDays === 0) return 'Today'
  if (diffDays === 1) return 'Yesterday'
  const d = new Date(ts)
  const y = d.getFullYear()
  const m = d.getMonth()
  const day = d.getDate()
  const sameYear = new Date(now).getFullYear() === y
  return sameYear ? `${MONTHS[m]}-${day}` : `${MONTHS[m]}-${day}-${y}`
}

/** 显示名基础（不含 offset），用于 identity 的 name */
function getBaseName(r: IRBRegion, idx?: number): string {
  const name =
    r.trans_name ??
    r.trans_id ??
    r.gene_name ??
    r.gene_id ??
    r.search ??
    (r.chr ? `${r.chr}:${r.start}-${r.end}` : idx != null ? `Match ${idx + 1}` : 'unknown')
  return String(name)
}

/** 主规则：`${name}:${offset}` */
function recordIdentity(r: IRBRegion, idx?: number): string {
  const base = getBaseName(r, idx)
  const off = r.offset !== undefined ? String(r.offset) : ''
  return `${base}:${off}`
}

/** 让出主线程（优先 idle，其次最小 timeout） */
function yieldToBrowser(useIdle = true): Promise<void> {
  if (useIdle && 'requestIdleCallback' in window) {
    return new Promise((resolve) => (window as any).requestIdleCallback(() => resolve()))
  }
  return new Promise((resolve) => setTimeout(resolve, 0))
}

export type FormatOptions = {
  chunkSize?: number // 每批处理多少条
  yieldWithIdle?: boolean // 是否用 requestIdleCallback
}

/**
 * Promise 版分片计算：
 * - 全量按 time 降序
 * - 按“天标签”分组
 * - 每分组基于 `${name}:${offset}` 去重：**当天同 identity 仅保留最新一条**
 * - 组内 & 组间均按时间降序
 */
export async function formatTreeDataAsync(
  raw: IRBRegion[] | undefined,
  opts: FormatOptions = {}
): Promise<HistoryGroup[]> {
  if (!raw || raw.length === 0) return []

  const { chunkSize = 1500, yieldWithIdle = true } = opts
  const sorted = [...raw].sort((a, b) => (b.time ?? 0) - (a.time ?? 0))

  // label -> (identity -> record)
  const bucket = new Map<string, Map<string, HistoryRecord>>()
  const bucketMax = new Map<string, number>()

  for (let i = 0; i < sorted.length; i++) {
    const r = sorted[i]
    const time = typeof r.time === 'number' ? r.time : 0
    const label = formatTimeLabel(time)
    const ident = recordIdentity(r, i)

    let labelMap = bucket.get(label)
    if (!labelMap) {
      labelMap = new Map()
      bucket.set(label, labelMap)
    }
    // 因为整体已按时间降序，第一次遇到即为当天该 identity 的最新记录
    if (!labelMap.has(ident)) {
      labelMap.set(ident, {
        id: r.id ?? `${ident}-${time}`,
        time,
        trans_id: r.trans_id,
        trans_name: r.trans_name,
        trans_type: r.trans_type,
        region: r
      })
      bucketMax.set(label, Math.max(bucketMax.get(label) ?? 0, time))
    }

    // 分片让步
    if (i % chunkSize === 0 && i !== 0) {
      // 让浏览器先渲染 / 处理输入事件
      // eslint-disable-next-line no-await-in-loop
      await yieldToBrowser(yieldWithIdle)
    }
  }

  // 组装输出
  const groups: HistoryGroup[] = []
  for (const [label, m] of bucket) {
    const arr = Array.from(m.values()).sort((a, b) => (b.time ?? 0) - (a.time ?? 0))
    groups.push({
      label,
      sortTime: bucketMax.get(label) ?? 0,
      items: arr
    })
  }

  groups.sort((a, b) => b.sortTime - a.sortTime)
  return groups
}
